export const CLIENT_BOARD_GEOMETRY_JS = "export const DEFAULT_BOARD_CAMERA = { zoom: 1, panX: 0, panY: 0 };\nexport const DEFAULT_TOUCH_HIT_TARGET_PX = 44;\nexport const MIN_BOARD_ZOOM = 0.5;\nexport const MAX_BOARD_ZOOM = 5;\nexport const clamp = (value, min, max) => Math.max(min, Math.min(max, value));\nexport const deriveBoardTransform = (board, camera, cssWidth, cssHeight) => {\n    const baseScale = Math.min(cssWidth / board.width, cssHeight / board.height);\n    const scale = baseScale * camera.zoom;\n    return {\n        scale,\n        x: (cssWidth - board.width * scale) / 2 + camera.panX,\n        y: (cssHeight - board.height * scale) / 2 + camera.panY\n    };\n};\nexport const screenToBoard = (screen, transform) => ({\n    x: (screen.x - transform.x) / transform.scale,\n    y: (screen.y - transform.y) / transform.scale\n});\nexport const clampPiecePosition = (board, piece, x, y) => ({\n    x: clamp(x, 0, Math.max(0, board.width - piece.width * piece.scale)),\n    y: clamp(y, 0, Math.max(0, board.height - piece.height * piece.scale))\n});\nexport const deriveCameraZoom = ({ board, camera, cssWidth, cssHeight, nextZoom, anchorScreen, minZoom = MIN_BOARD_ZOOM, maxZoom = MAX_BOARD_ZOOM }) => {\n    const beforeTransform = deriveBoardTransform(board, camera, cssWidth, cssHeight);\n    const anchor = anchorScreen || { x: cssWidth / 2, y: cssHeight / 2 };\n    const boardAnchor = screenToBoard(anchor, beforeTransform);\n    const zoom = clamp(nextZoom, minZoom, maxZoom);\n    const zoomedCamera = { ...camera, zoom };\n    const afterTransform = deriveBoardTransform(board, zoomedCamera, cssWidth, cssHeight);\n    return {\n        zoom,\n        panX: camera.panX +\n            anchor.x -\n            (afterTransform.x + boardAnchor.x * afterTransform.scale),\n        panY: camera.panY +\n            anchor.y -\n            (afterTransform.y + boardAnchor.y * afterTransform.scale)\n    };\n};\nexport const derivePieceTouchPadding = (piece, transform, pointerType, touchHitTargetPx = DEFAULT_TOUCH_HIT_TARGET_PX) => {\n    if (pointerType === 'mouse' || !transform)\n        return { x: 0, y: 0 };\n    const drawW = piece.width * piece.scale;\n    const drawH = piece.height * piece.scale;\n    const targetBoardSize = touchHitTargetPx / transform.scale;\n    return {\n        x: Math.max(0, (targetBoardSize - drawW) / 2),\n        y: Math.max(0, (targetBoardSize - drawH) / 2)\n    };\n};\nexport const findHitPiece = (point, pieces, transform = null, pointerType = 'mouse', touchHitTargetPx = DEFAULT_TOUCH_HIT_TARGET_PX) => [...pieces]\n    .sort((a, b) => b.z - a.z)\n    .find((piece) => {\n    const padding = derivePieceTouchPadding(piece, transform, pointerType, touchHitTargetPx);\n    return (point.x >= piece.x - padding.x &&\n        point.x <= piece.x + piece.width * piece.scale + padding.x &&\n        point.y >= piece.y - padding.y &&\n        point.y <= piece.y + piece.height * piece.scale + padding.y);\n}) || null;\n"
export const CLIENT_BOARD_VIEW_JS = "import { browserImageUrl } from './image-assets.js';\nexport const boardList = (state) => Object.values(state?.boards ?? {});\nexport const selectedBoardId = (state) => {\n    if (!state)\n        return null;\n    if (state.selectedBoardId && state.boards[state.selectedBoardId]) {\n        return state.selectedBoardId;\n    }\n    return boardList(state)[0]?.id ?? null;\n};\nexport const selectedBoard = (state) => {\n    const boardId = selectedBoardId(state);\n    return boardId ? (state?.boards[boardId] ?? null) : null;\n};\nexport const boardPieces = (state, board) => {\n    if (!state || !board)\n        return [];\n    const boardId = typeof board === 'string' ? board : board.id;\n    return Object.values(state.pieces)\n        .filter((piece) => piece.boardId === boardId)\n        .sort((left, right) => left.z - right.z);\n};\nexport const selectedBoardPieces = (state) => boardPieces(state, selectedBoard(state));\nexport const pieceImageUrl = (piece) => browserImageUrl(piece.imageAssetId);\nexport const boardImageUrl = (board) => browserImageUrl(board.url) || browserImageUrl(board.imageAssetId);\nexport const boardStatusLabel = (boards, board) => {\n    if (!board)\n        return 'No board';\n    const selectedIndex = boards.findIndex((candidate) => candidate.id === board.id);\n    return `${board.name} (${selectedIndex + 1}/${boards.length})`;\n};\nexport const boardOptionLabel = (board, index) => `B${index + 1} ${board.name}`;\nexport const boardSelectTitle = (board, canSelectBoards) => canSelectBoards ? board?.name || 'Board' : 'Board selection is referee-only';\n"
export const CLIENT_BOARD_CONTROLLER_JS = "import { DEFAULT_BOARD_CAMERA, clampPiecePosition, deriveBoardTransform, deriveCameraZoom, findHitPiece, screenToBoard } from './board-geometry.js';\nimport { buildMovePieceCommand } from '../game-commands.js';\nimport { boardImageUrl, pieceImageUrl, selectedBoard, selectedBoardPieces } from './board-view.js';\nimport { loadBrowserImage } from './image-assets.js';\nconst DRAG_START_SLOP_PX = 6;\nexport const DEFAULT_LOS_OVERLAY_CANVAS_STYLE = {\n    wallStroke: 'rgba(255, 255, 255, 0.72)',\n    closedDoorStroke: 'rgba(255, 119, 107, 0.9)',\n    openDoorStroke: 'rgba(72, 255, 173, 0.76)',\n    wallLineWidth: 3,\n    doorLineWidth: 4,\n    dashLength: 10,\n    gapLength: 7\n};\nexport const buildCompletedPieceDragMoveCommand = ({ drag, identity, state }) => {\n    if (!state || !drag.moved)\n        return null;\n    const x = Math.round(drag.x);\n    const y = Math.round(drag.y);\n    if (x === Math.round(drag.startX) && y === Math.round(drag.startY)) {\n        return null;\n    }\n    return buildMovePieceCommand({\n        identity,\n        state,\n        pieceId: drag.pieceId,\n        x,\n        y\n    });\n};\nexport const drawLosOverlaySegments = (ctx, segments, transform, style = DEFAULT_LOS_OVERLAY_CANVAS_STYLE) => {\n    if (segments.length === 0)\n        return;\n    ctx.save();\n    ctx.lineCap = 'round';\n    for (const segment of segments) {\n        ctx.strokeStyle =\n            segment.type === 'wall'\n                ? style.wallStroke\n                : segment.open\n                    ? style.openDoorStroke\n                    : style.closedDoorStroke;\n        ctx.lineWidth =\n            (segment.type === 'wall' ? style.wallLineWidth : style.doorLineWidth) /\n                transform.scale;\n        ctx.setLineDash(segment.type === 'door' && segment.open\n            ? [style.dashLength / transform.scale, style.gapLength / transform.scale]\n            : []);\n        ctx.beginPath();\n        ctx.moveTo(segment.x1, segment.y1);\n        ctx.lineTo(segment.x2, segment.y2);\n        ctx.stroke();\n    }\n    ctx.setLineDash([]);\n    ctx.restore();\n};\nexport const createBoardController = ({ canvas, context: ctx, getState, getIdentity, getSelectedPieceId, setSelectedPieceId, sendCommand, setError, requestRender, devicePixelRatio = () => window.devicePixelRatio || 1 }) => {\n    let drag = null;\n    let boardCamera = { ...DEFAULT_BOARD_CAMERA };\n    let cameraBoardId = null;\n    const boardImageCache = new Map();\n    const pieceImageCache = new Map();\n    const currentBoard = () => selectedBoard(getState());\n    const currentPieces = () => selectedBoardPieces(getState());\n    const loadImage = (url, cache) => loadBrowserImage(url, cache, requestRender);\n    const loadBoardImage = (board) => loadImage(boardImageUrl(board), boardImageCache);\n    const loadPieceImage = (piece) => loadImage(pieceImageUrl(piece), pieceImageCache);\n    const resetCamera = () => {\n        boardCamera = { ...DEFAULT_BOARD_CAMERA };\n    };\n    const ensureBoardCamera = (board) => {\n        if (!board || cameraBoardId === board.id)\n            return;\n        cameraBoardId = board.id;\n        resetCamera();\n    };\n    const canvasCssSize = () => {\n        const rect = canvas.getBoundingClientRect();\n        return {\n            width: Math.max(1, Math.floor(rect.width)),\n            height: Math.max(1, Math.floor(rect.height))\n        };\n    };\n    const boardTransform = (board, cssWidth, cssHeight) => deriveBoardTransform(board, boardCamera, cssWidth, cssHeight);\n    const screenPoint = (event) => {\n        const rect = canvas.getBoundingClientRect();\n        return {\n            x: event.clientX - rect.left,\n            y: event.clientY - rect.top\n        };\n    };\n    const canvasPoint = (event) => {\n        const board = currentBoard();\n        if (!board)\n            return { x: 0, y: 0 };\n        const size = canvasCssSize();\n        return screenToBoard(screenPoint(event), boardTransform(board, size.width, size.height));\n    };\n    const clampDraggedPiecePosition = (piece, x, y) => {\n        const board = currentBoard();\n        if (!board)\n            return { x, y };\n        return clampPiecePosition(board, piece, x, y);\n    };\n    const releaseCanvasPointer = (pointerId) => {\n        if (canvas.hasPointerCapture(pointerId)) {\n            canvas.releasePointerCapture(pointerId);\n        }\n    };\n    const hitPiece = (point, transform = null, pointerType = 'mouse') => findHitPiece(point, currentPieces(), transform, pointerType);\n    const drawGrid = (board) => {\n        const grid = Math.max(25, board.scale || 50);\n        ctx.strokeStyle = 'rgba(238, 244, 241, 0.08)';\n        ctx.lineWidth = 1;\n        for (let x = 0; x <= board.width; x += grid) {\n            ctx.beginPath();\n            ctx.moveTo(x, 0);\n            ctx.lineTo(x, board.height);\n            ctx.stroke();\n        }\n        for (let y = 0; y <= board.height; y += grid) {\n            ctx.beginPath();\n            ctx.moveTo(0, y);\n            ctx.lineTo(board.width, y);\n            ctx.stroke();\n        }\n    };\n    const renderPiece = (piece, transform) => {\n        const isSelected = piece.id === getSelectedPieceId();\n        const drawX = drag && drag.kind === 'piece' && drag.pieceId === piece.id\n            ? drag.x\n            : piece.x;\n        const drawY = drag && drag.kind === 'piece' && drag.pieceId === piece.id\n            ? drag.y\n            : piece.y;\n        const drawW = piece.width * piece.scale;\n        const drawH = piece.height * piece.scale;\n        const radius = Math.min(10, drawW / 3, drawH / 3);\n        const image = loadPieceImage(piece);\n        if (isSelected) {\n            ctx.save();\n            ctx.shadowColor = 'rgba(72, 255, 173, 0.88)';\n            ctx.shadowBlur = 18 / transform.scale;\n            ctx.strokeStyle = 'rgba(72, 255, 173, 0.95)';\n            ctx.lineWidth = 8 / transform.scale;\n            ctx.beginPath();\n            ctx.roundRect(drawX - 4, drawY - 4, drawW + 8, drawH + 8, radius + 4);\n            ctx.stroke();\n            ctx.restore();\n        }\n        ctx.fillStyle = piece.visibility === 'PREVIEW' ? '#f2b84b' : '#5fd0a2';\n        ctx.strokeStyle = isSelected ? '#f7fff9' : '#0b1211';\n        ctx.lineWidth = (isSelected ? 3 : 2) / transform.scale;\n        ctx.beginPath();\n        ctx.roundRect(drawX, drawY, drawW, drawH, radius);\n        ctx.fill();\n        if (image) {\n            ctx.save();\n            ctx.clip();\n            ctx.drawImage(image, drawX, drawY, drawW, drawH);\n            ctx.restore();\n        }\n        ctx.stroke();\n        if (isSelected) {\n            const corner = Math.min(drawW, drawH, 12);\n            ctx.strokeStyle = '#48ffad';\n            ctx.lineWidth = 2 / transform.scale;\n            ctx.beginPath();\n            ctx.moveTo(drawX, drawY + corner);\n            ctx.lineTo(drawX, drawY);\n            ctx.lineTo(drawX + corner, drawY);\n            ctx.moveTo(drawX + drawW - corner, drawY);\n            ctx.lineTo(drawX + drawW, drawY);\n            ctx.lineTo(drawX + drawW, drawY + corner);\n            ctx.moveTo(drawX + drawW, drawY + drawH - corner);\n            ctx.lineTo(drawX + drawW, drawY + drawH);\n            ctx.lineTo(drawX + drawW - corner, drawY + drawH);\n            ctx.moveTo(drawX + corner, drawY + drawH);\n            ctx.lineTo(drawX, drawY + drawH);\n            ctx.lineTo(drawX, drawY + drawH - corner);\n            ctx.stroke();\n        }\n        if (!image) {\n            ctx.fillStyle = '#07100d';\n            ctx.font = '700 13px system-ui';\n            ctx.fillText(piece.name, drawX + 8, drawY + 22);\n        }\n    };\n    const render = () => {\n        const board = currentBoard();\n        ensureBoardCamera(board);\n        const size = canvasCssSize();\n        const dpr = devicePixelRatio();\n        const cssWidth = size.width;\n        const cssHeight = size.height;\n        if (canvas.width !== cssWidth * dpr || canvas.height !== cssHeight * dpr) {\n            canvas.width = cssWidth * dpr;\n            canvas.height = cssHeight * dpr;\n        }\n        ctx.setTransform(dpr, 0, 0, dpr, 0, 0);\n        ctx.clearRect(0, 0, cssWidth, cssHeight);\n        if (!board) {\n            ctx.fillStyle = '#253130';\n            ctx.fillRect(0, 0, cssWidth, cssHeight);\n            ctx.fillStyle = '#a6b4af';\n            ctx.font = '16px system-ui';\n            ctx.fillText('Open or bootstrap a room from the menu', 24, 34);\n            return;\n        }\n        const transform = boardTransform(board, cssWidth, cssHeight);\n        ctx.fillStyle = '#253130';\n        ctx.fillRect(0, 0, cssWidth, cssHeight);\n        ctx.save();\n        ctx.translate(transform.x, transform.y);\n        ctx.scale(transform.scale, transform.scale);\n        ctx.fillStyle = '#06100d';\n        ctx.fillRect(0, 0, board.width, board.height);\n        const boardImage = loadBoardImage(board);\n        if (boardImage) {\n            ctx.drawImage(boardImage, 0, 0, board.width, board.height);\n        }\n        drawGrid(board);\n        for (const piece of currentPieces()) {\n            renderPiece(piece, transform);\n        }\n        ctx.restore();\n    };\n    const setCameraZoom = (nextZoom, anchorScreen = null) => {\n        const board = currentBoard();\n        if (!board)\n            return;\n        const size = canvasCssSize();\n        boardCamera = deriveCameraZoom({\n            board,\n            camera: boardCamera,\n            cssWidth: size.width,\n            cssHeight: size.height,\n            nextZoom,\n            anchorScreen\n        });\n        requestRender();\n    };\n    canvas.addEventListener('pointerdown', (event) => {\n        if (event.button !== 0)\n            return;\n        event.preventDefault();\n        const screen = screenPoint(event);\n        const board = currentBoard();\n        const size = canvasCssSize();\n        const transform = board\n            ? boardTransform(board, size.width, size.height)\n            : null;\n        const point = board && transform ? screenToBoard(screen, transform) : { x: 0, y: 0 };\n        const piece = hitPiece(point, transform, event.pointerType);\n        setSelectedPieceId(piece?.id || null);\n        if (piece) {\n            drag = {\n                kind: 'piece',\n                pieceId: piece.id,\n                offsetX: point.x - piece.x,\n                offsetY: point.y - piece.y,\n                startPointerX: screen.x,\n                startPointerY: screen.y,\n                moved: false,\n                x: piece.x,\n                y: piece.y,\n                startX: piece.x,\n                startY: piece.y\n            };\n        }\n        else {\n            drag = {\n                kind: 'pan',\n                pointerX: screen.x,\n                pointerY: screen.y,\n                startPointerX: screen.x,\n                startPointerY: screen.y,\n                moved: false,\n                panX: boardCamera.panX,\n                panY: boardCamera.panY\n            };\n        }\n        canvas.setPointerCapture(event.pointerId);\n        requestRender();\n    });\n    canvas.addEventListener('pointermove', (event) => {\n        if (!drag)\n            return;\n        event.preventDefault();\n        const screen = screenPoint(event);\n        if (!drag.moved) {\n            drag.moved =\n                Math.hypot(screen.x - drag.startPointerX, screen.y - drag.startPointerY) >= DRAG_START_SLOP_PX;\n        }\n        if (drag.kind === 'pan') {\n            boardCamera.panX = drag.panX + screen.x - drag.pointerX;\n            boardCamera.panY = drag.panY + screen.y - drag.pointerY;\n            requestRender();\n            return;\n        }\n        const point = canvasPoint(event);\n        const next = clampDraggedPiecePosition(getState()?.pieces?.[drag.pieceId] || { width: 0, height: 0, scale: 1 }, point.x - drag.offsetX, point.y - drag.offsetY);\n        drag.x = next.x;\n        drag.y = next.y;\n        requestRender();\n    });\n    canvas.addEventListener('pointerup', (event) => {\n        if (!drag)\n            return;\n        event.preventDefault();\n        const completed = drag;\n        drag = null;\n        releaseCanvasPointer(event.pointerId);\n        if (completed.kind !== 'piece') {\n            requestRender();\n            return;\n        }\n        const command = buildCompletedPieceDragMoveCommand({\n            drag: completed,\n            identity: getIdentity(),\n            state: getState()\n        });\n        if (!command) {\n            requestRender();\n            return;\n        }\n        sendCommand(command)\n            .catch((error) => setError(error.message))\n            .finally(requestRender);\n    });\n    canvas.addEventListener('pointercancel', (event) => {\n        drag = null;\n        releaseCanvasPointer(event.pointerId);\n        requestRender();\n    });\n    canvas.addEventListener('wheel', (event) => {\n        event.preventDefault();\n        const zoomFactor = event.deltaY < 0 ? 1.12 : 1 / 1.12;\n        setCameraZoom(boardCamera.zoom * zoomFactor, screenPoint(event));\n    }, { passive: false });\n    return {\n        clearDrag: () => {\n            drag = null;\n        },\n        currentZoom: () => boardCamera.zoom,\n        selectedPiece: () => {\n            const pieces = currentPieces();\n            const selectedPieceId = getSelectedPieceId();\n            return (pieces.find((piece) => piece.id === selectedPieceId) ||\n                pieces[0] ||\n                null);\n        },\n        render,\n        resetCamera,\n        setCameraZoom\n    };\n};\n"
export const CLIENT_BOOTSTRAP_FLOW_JS = "const idFromName = (name, fallback) => name\n    .toLowerCase()\n    .replace(/[^a-z0-9]+/g, '-')\n    .replace(/^-|-$/g, '') || fallback;\nconst scoutCharacterId = 'scout';\nexport const createGameCommand = ({ roomId, actorId }) => ({\n    type: 'CreateGame',\n    gameId: roomId,\n    actorId,\n    slug: roomId,\n    name: `Cepheus Room ${roomId}`\n});\nexport const createBoardCommand = ({ roomId, actorId }) => ({\n    type: 'CreateBoard',\n    gameId: roomId,\n    actorId,\n    boardId: 'main-board',\n    name: 'Downport Skirmish',\n    width: 1200,\n    height: 800,\n    scale: 50\n});\nexport const createCharacterCommand = ({ roomId, actorId }) => ({\n    type: 'CreateCharacter',\n    gameId: roomId,\n    actorId,\n    characterId: scoutCharacterId,\n    characterType: 'PLAYER',\n    name: 'Scout'\n});\nexport const updateScoutSheetCommand = ({ roomId, actorId }) => ({\n    type: 'UpdateCharacterSheet',\n    gameId: roomId,\n    actorId,\n    characterId: scoutCharacterId,\n    age: 34,\n    characteristics: {\n        str: 7,\n        dex: 8,\n        end: 8,\n        int: 7,\n        edu: 9,\n        soc: 6\n    },\n    skills: ['Vacc Suit-0', 'Gun Combat-0', 'Mechanic-0', 'Recon-0'],\n    equipment: [\n        { name: 'Vacc Suit', quantity: 1, notes: 'Carried' },\n        { name: 'Laser Carbine', quantity: 1, notes: 'Carried' },\n        { name: 'Medkit', quantity: 1, notes: 'Stowed' }\n    ],\n    credits: 1200\n});\nexport const startScoutCreationCommand = ({ roomId, actorId }) => ({\n    type: 'StartCharacterCreation',\n    gameId: roomId,\n    actorId,\n    characterId: scoutCharacterId\n});\nexport const setScoutCharacteristicsCreationCommand = ({ roomId, actorId }) => ({\n    type: 'AdvanceCharacterCreation',\n    gameId: roomId,\n    actorId,\n    characterId: scoutCharacterId,\n    creationEvent: { type: 'SET_CHARACTERISTICS' }\n});\nexport const completeScoutHomeworldCreationCommand = ({ roomId, actorId }) => ({\n    type: 'AdvanceCharacterCreation',\n    gameId: roomId,\n    actorId,\n    characterId: scoutCharacterId,\n    creationEvent: { type: 'COMPLETE_HOMEWORLD' }\n});\nexport const startScoutCareerTermCommand = ({ roomId, actorId }) => ({\n    type: 'StartCharacterCareerTerm',\n    gameId: roomId,\n    actorId,\n    characterId: scoutCharacterId,\n    career: 'Scout'\n});\nexport const selectScoutCareerCreationCommand = ({ roomId, actorId }) => ({\n    type: 'AdvanceCharacterCreation',\n    gameId: roomId,\n    actorId,\n    characterId: scoutCharacterId,\n    creationEvent: { type: 'SELECT_CAREER', isNewCareer: true }\n});\nexport const createPieceCommand = ({ roomId, actorId }, boardId) => ({\n    type: 'CreatePiece',\n    gameId: roomId,\n    actorId,\n    pieceId: 'scout-1',\n    boardId,\n    name: 'Scout',\n    characterId: scoutCharacterId,\n    imageAssetId: null,\n    x: 220,\n    y: 180\n});\nexport const uniqueBoardId = (state, name) => {\n    const base = idFromName(name, 'board');\n    let index = Object.keys(state?.boards || {}).length + 1;\n    let boardId = `${base}-${index}`;\n    while (state?.boards?.[boardId]) {\n        index += 1;\n        boardId = `${base}-${index}`;\n    }\n    return boardId;\n};\nexport const uniquePieceId = (state, name) => {\n    const base = idFromName(name, 'piece');\n    let index = Object.keys(state?.pieces || {}).length + 1;\n    let pieceId = `${base}-${index}`;\n    while (state?.pieces?.[pieceId]) {\n        index += 1;\n        pieceId = `${base}-${index}`;\n    }\n    return pieceId;\n};\nexport const uniqueCharacterId = (state, name) => {\n    const base = idFromName(name, 'character');\n    let index = Object.keys(state?.characters || {}).length + 1;\n    let characterId = `${base}-${index}`;\n    while (state?.characters?.[characterId]) {\n        index += 1;\n        characterId = `${base}-${index}`;\n    }\n    return characterId;\n};\nexport const parsePositiveIntegerValue = (value, fallback) => {\n    const parsed = Number.parseInt(value, 10);\n    return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;\n};\nexport const parsePositiveNumberValue = (value, fallback) => {\n    const parsed = Number.parseFloat(value);\n    return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;\n};\nexport const parseNonNegativeIntegerValue = (value, fallback) => {\n    const parsed = Number.parseInt(value, 10);\n    return Number.isFinite(parsed) && parsed >= 0 ? parsed : fallback;\n};\nexport const nextBootstrapCommand = ({ roomId, actorId, state }) => {\n    const commandContext = { roomId, actorId };\n    if (!state)\n        return createGameCommand(commandContext);\n    const boardIds = Object.keys(state.boards || {});\n    if (boardIds.length === 0)\n        return createBoardCommand(commandContext);\n    const scout = state.characters[scoutCharacterId];\n    if (!scout)\n        return createCharacterCommand(commandContext);\n    if (!scout.creation)\n        return startScoutCreationCommand(commandContext);\n    if (scout.creation.state.status === 'CHARACTERISTICS') {\n        return setScoutCharacteristicsCreationCommand(commandContext);\n    }\n    if (scout.creation.state.status === 'HOMEWORLD') {\n        return completeScoutHomeworldCreationCommand(commandContext);\n    }\n    if (scout.creation.terms.length === 0) {\n        return startScoutCareerTermCommand(commandContext);\n    }\n    if (scout.creation.state.status === 'CAREER_SELECTION') {\n        return selectScoutCareerCreationCommand(commandContext);\n    }\n    if ((scout.skills || []).length === 0) {\n        return updateScoutSheetCommand(commandContext);\n    }\n    if (Object.keys(state.pieces || {}).length === 0) {\n        return createPieceCommand(commandContext, state.selectedBoardId && state.boards[state.selectedBoardId]\n            ? state.selectedBoardId\n            : boardIds[0]);\n    }\n    return null;\n};\n"
export const CLIENT_CHARACTER_CREATION_ACTIONS_JS = "const statusLabel = (status) => status\n    .toLowerCase()\n    .split('_')\n    .map((part) => part.slice(0, 1).toUpperCase() + part.slice(1))\n    .join(' ');\nconst advanceCommand = (identity, character, creationEvent) => ({\n    type: 'AdvanceCharacterCreation',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    characterId: character.id,\n    creationEvent\n});\nconst action = (key, label, command, variant = 'primary') => ({\n    key,\n    label,\n    command,\n    variant\n});\nexport const deriveCharacterCreationActionPlan = (identity, character) => {\n    if (!character)\n        return null;\n    if (!character.creation) {\n        return {\n            title: 'Creation',\n            status: 'Not started',\n            summary: 'Start the character creation lifecycle for this sheet.',\n            actions: [\n                action('start', 'Start creation', {\n                    type: 'StartCharacterCreation',\n                    gameId: identity.gameId,\n                    actorId: identity.actorId,\n                    characterId: character.id\n                })\n            ]\n        };\n    }\n    const { status } = character.creation.state;\n    const summary = character.creation.creationComplete\n        ? 'Creation is complete and the character is playable.'\n        : 'Advance the server-backed character creation state.';\n    const plan = (actions) => ({\n        title: 'Creation',\n        status: statusLabel(status),\n        summary,\n        actions\n    });\n    switch (status) {\n        case 'CHARACTERISTICS':\n            return plan([\n                action('set-characteristics', 'Confirm characteristics', advanceCommand(identity, character, { type: 'SET_CHARACTERISTICS' }))\n            ]);\n        case 'HOMEWORLD':\n            return plan([\n                action('complete-homeworld', 'Confirm homeworld', advanceCommand(identity, character, { type: 'COMPLETE_HOMEWORLD' }))\n            ]);\n        case 'CAREER_SELECTION':\n            if (character.creation.terms.length === 0) {\n                return plan([\n                    action('start-scout-term', 'Start Scout term', {\n                        type: 'StartCharacterCareerTerm',\n                        gameId: identity.gameId,\n                        actorId: identity.actorId,\n                        characterId: character.id,\n                        career: 'Scout'\n                    })\n                ]);\n            }\n            return plan([\n                action('select-career', 'Select career', advanceCommand(identity, character, {\n                    type: 'SELECT_CAREER',\n                    isNewCareer: true\n                }))\n            ]);\n        case 'BASIC_TRAINING':\n            return plan([\n                action('complete-basic-training', 'Complete basic training', advanceCommand(identity, character, {\n                    type: 'COMPLETE_BASIC_TRAINING'\n                }))\n            ]);\n        case 'SURVIVAL':\n            return plan([\n                action('survival-passed', 'Pass survival', advanceCommand(identity, character, {\n                    type: 'SURVIVAL_PASSED',\n                    canCommission: false,\n                    canAdvance: true\n                })),\n                action('survival-failed', 'Fail survival', advanceCommand(identity, character, { type: 'SURVIVAL_FAILED' }), 'secondary')\n            ]);\n        case 'MISHAP':\n            return plan([\n                action('resolve-mishap', 'Resolve mishap', advanceCommand(identity, character, { type: 'MISHAP_RESOLVED' })),\n                action('death-confirmed', 'Confirm death', advanceCommand(identity, character, { type: 'DEATH_CONFIRMED' }), 'secondary')\n            ]);\n        case 'COMMISSION':\n            return plan([\n                action('skip-commission', 'Skip commission', advanceCommand(identity, character, { type: 'SKIP_COMMISSION' })),\n                action('complete-commission', 'Complete commission', advanceCommand(identity, character, { type: 'COMPLETE_COMMISSION' }), 'secondary')\n            ]);\n        case 'ADVANCEMENT':\n            return plan([\n                action('complete-advancement', 'Complete advancement', advanceCommand(identity, character, { type: 'COMPLETE_ADVANCEMENT' })),\n                action('skip-advancement', 'Skip advancement', advanceCommand(identity, character, { type: 'SKIP_ADVANCEMENT' }), 'secondary')\n            ]);\n        case 'SKILLS_TRAINING':\n            return plan([\n                action('complete-skills', 'Complete skills', advanceCommand(identity, character, { type: 'COMPLETE_SKILLS' }))\n            ]);\n        case 'AGING':\n            return plan([\n                action('complete-aging', 'Complete aging', advanceCommand(identity, character, { type: 'COMPLETE_AGING' }))\n            ]);\n        case 'REENLISTMENT':\n            return plan([\n                action('leave-career', 'Leave career', advanceCommand(identity, character, { type: 'LEAVE_CAREER' })),\n                action('reenlist', 'Re-enlist', advanceCommand(identity, character, { type: 'REENLIST' }), 'secondary')\n            ]);\n        case 'MUSTERING_OUT':\n            return plan([\n                action('finish-mustering', 'Finish mustering out', advanceCommand(identity, character, { type: 'FINISH_MUSTERING' })),\n                action('continue-career', 'Continue career', advanceCommand(identity, character, { type: 'CONTINUE_CAREER' }), 'secondary')\n            ]);\n        case 'ACTIVE':\n            return plan([\n                action('creation-complete', 'Make playable', advanceCommand(identity, character, { type: 'CREATION_COMPLETE' }))\n            ]);\n        case 'PLAYABLE':\n            return plan([]);\n        case 'DECEASED':\n            return {\n                title: 'Creation',\n                status: 'Deceased',\n                summary: 'Creation ended with this character deceased.',\n                actions: []\n            };\n        default: {\n            const exhaustive = status;\n            return exhaustive;\n        }\n    }\n};\n"
export const CLIENT_CHARACTER_COMMAND_PLAN_JS = "import { evaluateCareerCheck, parseCareerCheck } from '../../shared/character-creation/career-rules.js';\nimport { CEPHEUS_SRD_CAREERS } from '../../shared/character-creation/cepheus-srd-ruleset.js';\nimport { normalizeCareerSkill, tallyCareerSkills } from '../../shared/character-creation/skills.js';\nimport { uniqueCharacterId, uniquePieceId } from './bootstrap-flow.js';\nimport { createCharacterCreationFlow, deriveCharacterSheetPatch, validateCurrentCharacterCreationStep } from './character-creation-flow.js';\nconst GENERATED_NAMES = [\n    'Mae',\n    'Fred',\n    'Zoop',\n    'Erit',\n    'Kade',\n    'Nia',\n    'Rook',\n    'Vera',\n    'Sable',\n    'Tamsin',\n    'Juno',\n    'Mara'\n];\nconst sequenceCommandAt = (command, state, offset) => {\n    if (command.expectedSeq !== undefined || command.type === 'CreateGame') {\n        return command;\n    }\n    return {\n        ...command,\n        expectedSeq: state.eventSeq + offset\n    };\n};\nconst playableCreationCommands = (identity, characterId, outcome = {\n    survivalPassed: true,\n    canCommission: false,\n    commissionPassed: null,\n    canAdvance: true,\n    advancementPassed: true\n}) => {\n    const advance = (creationEvent) => ({\n        type: 'AdvanceCharacterCreation',\n        gameId: identity.gameId,\n        actorId: identity.actorId,\n        characterId,\n        creationEvent\n    });\n    const commands = [advance({ type: 'COMPLETE_BASIC_TRAINING' })];\n    if (!outcome.survivalPassed) {\n        return [\n            ...commands,\n            advance({ type: 'SURVIVAL_FAILED' }),\n            advance({ type: 'MISHAP_RESOLVED' }),\n            advance({ type: 'FINISH_MUSTERING' }),\n            advance({ type: 'CREATION_COMPLETE' })\n        ];\n    }\n    commands.push(advance({\n        type: 'SURVIVAL_PASSED',\n        canCommission: outcome.canCommission,\n        canAdvance: outcome.canAdvance\n    }));\n    if (outcome.canCommission) {\n        commands.push(advance({\n            type: outcome.commissionPassed\n                ? 'COMPLETE_COMMISSION'\n                : 'SKIP_COMMISSION'\n        }));\n    }\n    else if (outcome.canAdvance) {\n        commands.push(advance({\n            type: outcome.advancementPassed\n                ? 'COMPLETE_ADVANCEMENT'\n                : 'SKIP_ADVANCEMENT'\n        }));\n    }\n    commands.push(advance({ type: 'COMPLETE_SKILLS' }), advance({ type: 'COMPLETE_AGING' }), advance({ type: 'LEAVE_CAREER' }), advance({ type: 'FINISH_MUSTERING' }), advance({ type: 'CREATION_COMPLETE' }));\n    return commands;\n};\nconst initialCreationCommands = ({ identity, state, characterId, characterType, name, age, career, drafted, characteristics, skills, equipment, credits, notes }) => {\n    const flow = {\n        ...createCharacterCreationFlow(characterId, {\n            name,\n            characterType,\n            age,\n            characteristics,\n            skills,\n            equipment,\n            credits,\n            notes\n        }),\n        step: 'review'\n    };\n    return [\n        {\n            type: 'CreateCharacter',\n            gameId: identity.gameId,\n            actorId: identity.actorId,\n            characterId,\n            characterType,\n            name\n        },\n        {\n            type: 'StartCharacterCreation',\n            gameId: identity.gameId,\n            actorId: identity.actorId,\n            characterId\n        },\n        {\n            type: 'AdvanceCharacterCreation',\n            gameId: identity.gameId,\n            actorId: identity.actorId,\n            characterId,\n            creationEvent: { type: 'SET_CHARACTERISTICS' }\n        },\n        {\n            type: 'AdvanceCharacterCreation',\n            gameId: identity.gameId,\n            actorId: identity.actorId,\n            characterId,\n            creationEvent: { type: 'COMPLETE_HOMEWORLD' }\n        },\n        {\n            type: 'StartCharacterCareerTerm',\n            gameId: identity.gameId,\n            actorId: identity.actorId,\n            characterId,\n            career,\n            drafted\n        },\n        {\n            type: 'AdvanceCharacterCreation',\n            gameId: identity.gameId,\n            actorId: identity.actorId,\n            characterId,\n            creationEvent: { type: 'SELECT_CAREER', isNewCareer: true, drafted }\n        },\n        {\n            type: 'UpdateCharacterSheet',\n            gameId: identity.gameId,\n            actorId: identity.actorId,\n            characterId,\n            age: flow.draft.age,\n            ...deriveCharacterSheetPatch(flow.draft)\n        }\n    ].map((command, index) => sequenceCommandAt(command, state, index));\n};\nconst randomInt = (rng, maxExclusive) => Math.floor(rng() * maxExclusive);\nconst rollDie = (rng) => randomInt(rng, 6) + 1;\nconst roll2d6 = (rng) => rollDie(rng) + rollDie(rng);\nconst selectFrom = (rng, values) => values[randomInt(rng, values.length)];\nconst shuffledCareers = (rng) => {\n    const careers = [...CEPHEUS_SRD_CAREERS];\n    for (let index = careers.length - 1; index > 0; index--) {\n        const swapIndex = randomInt(rng, index + 1);\n        const current = careers[index];\n        careers[index] = careers[swapIndex];\n        careers[swapIndex] = current;\n    }\n    return careers;\n};\nconst normalizeGeneratedSkill = (skill, level = 0) => {\n    return normalizeCareerSkill(skill, level);\n};\nconst addSkill = (skills, skill, level = 0) => {\n    const normalized = normalizeGeneratedSkill(skill, level);\n    if (normalized)\n        skills.push(normalized);\n};\nconst applyPersonalDevelopment = (characteristics, entry) => {\n    const characteristic = /^\\+1 (Str|Dex|End|Int|Edu|Soc)$/i.exec(entry);\n    if (!characteristic)\n        return null;\n    const key = characteristic[1].toLowerCase();\n    characteristics[key] = (characteristics[key] ?? 0) + 1;\n    return `${characteristic[1]} +1`;\n};\nconst chooseQualifiedCareer = ({ rng, characteristics, notes }) => {\n    for (const career of shuffledCareers(rng)) {\n        const qualificationRoll = roll2d6(rng);\n        const outcome = evaluateCareerCheck({\n            check: career.qualification,\n            characteristics,\n            roll: qualificationRoll\n        });\n        if (!outcome)\n            continue;\n        notes.push(`${career.name} qualification: ${qualificationRoll} + ${outcome.modifier} = ${outcome.total} vs ${career.qualification} (${outcome.success ? 'passed' : 'failed'})`);\n        if (outcome.success) {\n            return { career, qualificationRoll, drafted: false };\n        }\n    }\n    const drifter = CEPHEUS_SRD_CAREERS.find((career) => career.name === 'Drifter') ??\n        CEPHEUS_SRD_CAREERS[0];\n    const qualificationRoll = roll2d6(rng);\n    notes.push('No preferred career qualification succeeded; drafted into Drifter.');\n    return { career: drifter, qualificationRoll, drafted: true };\n};\nconst resolveCareerRoll = ({ check, characteristics, roll }) => evaluateCareerCheck({\n    check,\n    characteristics,\n    roll\n});\nexport const generateCharacterPreview = ({ state, name, rng = Math.random }) => {\n    const notes = [\n        'Generated by the Cepheus Online character generator.'\n    ];\n    const characteristics = {\n        str: roll2d6(rng),\n        dex: roll2d6(rng),\n        end: roll2d6(rng),\n        int: roll2d6(rng),\n        edu: roll2d6(rng),\n        soc: roll2d6(rng)\n    };\n    notes.push(`Characteristics: Str ${characteristics.str}, Dex ${characteristics.dex}, End ${characteristics.end}, Int ${characteristics.int}, Edu ${characteristics.edu}, Soc ${characteristics.soc}.`);\n    const { career, qualificationRoll, drafted } = chooseQualifiedCareer({\n        rng,\n        characteristics,\n        notes\n    });\n    const skills = [];\n    for (const skill of career.serviceSkills)\n        addSkill(skills, skill, 0);\n    const trainingTables = [\n        career.personalDevelopment,\n        career.serviceSkills,\n        career.specialistSkills,\n        career.advancedEducation\n    ];\n    const trainingTable = selectFrom(rng, trainingTables);\n    const trainingEntry = selectFrom(rng, trainingTable);\n    const characteristicGain = applyPersonalDevelopment(characteristics, trainingEntry);\n    if (characteristicGain) {\n        notes.push(`Training: ${characteristicGain}.`);\n    }\n    else {\n        addSkill(skills, trainingEntry, 1);\n        notes.push(`Training: ${trainingEntry.replace('*', '')}.`);\n    }\n    const survivalRoll = roll2d6(rng);\n    const survival = resolveCareerRoll({\n        check: career.survival,\n        characteristics,\n        roll: survivalRoll\n    });\n    const survivalPassed = survival?.success ?? true;\n    notes.push(`${career.name} survival: ${survivalRoll} + ${survival?.modifier ?? 0} = ${survival?.total ?? survivalRoll} vs ${career.survival} (${survivalPassed ? 'passed' : 'mishap'}).`);\n    const canCommission = survivalPassed && parseCareerCheck(career.commission) !== null;\n    const commissionRoll = canCommission ? roll2d6(rng) : null;\n    const commission = commissionRoll === null\n        ? null\n        : resolveCareerRoll({\n            check: career.commission,\n            characteristics,\n            roll: commissionRoll\n        });\n    const commissionPassed = commission?.success ?? null;\n    if (commissionRoll !== null && commission) {\n        notes.push(`${career.name} commission: ${commissionRoll} + ${commission.modifier} = ${commission.total} vs ${career.commission} (${commissionPassed ? 'passed' : 'not commissioned'}).`);\n    }\n    const canAdvance = survivalPassed &&\n        !canCommission &&\n        parseCareerCheck(career.advancement) !== null;\n    const advancementRoll = canAdvance ? roll2d6(rng) : null;\n    const advancement = advancementRoll === null\n        ? null\n        : resolveCareerRoll({\n            check: career.advancement,\n            characteristics,\n            roll: advancementRoll\n        });\n    const advancementPassed = advancement?.success ?? null;\n    if (advancementRoll !== null && advancement) {\n        notes.push(`${career.name} advancement: ${advancementRoll} + ${advancement.modifier} = ${advancement.total} vs ${career.advancement} (${advancementPassed ? 'advanced' : 'held rank'}).`);\n    }\n    const cashRoll = rollDie(rng);\n    const credits = cashRoll * 1000;\n    notes.push(`Mustering out cash: ${cashRoll}000 credits.`);\n    return {\n        name: (name ?? '').trim() ||\n            `${selectFrom(rng, GENERATED_NAMES)} ${Object.keys(state?.characters ?? {}).length + 1}`,\n        career: career.name,\n        age: 22,\n        characteristics,\n        skills: tallyCareerSkills(skills),\n        credits,\n        notes: notes.join('\\n'),\n        qualificationRoll,\n        survivalRoll,\n        survivalPassed,\n        commissionRoll,\n        commissionPassed,\n        advancementRoll,\n        advancementPassed,\n        creationOutcome: {\n            survivalPassed,\n            canCommission,\n            commissionPassed,\n            canAdvance,\n            advancementPassed\n        },\n        drafted\n    };\n};\nexport const planCreatePlayableCharacterCommands = ({ identity, state, board, name, characterType, age, characteristics, skills, equipment, credits, notes, createLinkedPiece, existingPieceCount, career, drafted = false, creationOutcome }) => {\n    if (!state) {\n        return {\n            ok: false,\n            error: 'Open or create a room before creating a character',\n            focus: null\n        };\n    }\n    const trimmedName = name.trim();\n    if (!trimmedName) {\n        return {\n            ok: false,\n            error: 'Character name is required',\n            focus: 'name'\n        };\n    }\n    if (skills.length === 0) {\n        return {\n            ok: false,\n            error: 'At least one skill is required',\n            focus: 'skills'\n        };\n    }\n    const characterId = uniqueCharacterId(state, trimmedName);\n    const validation = validateCurrentCharacterCreationStep({\n        ...createCharacterCreationFlow(characterId, {\n            name: trimmedName,\n            characterType,\n            age,\n            characteristics,\n            skills,\n            equipment,\n            credits,\n            notes\n        }),\n        step: 'review'\n    });\n    if (!validation.ok) {\n        return {\n            ok: false,\n            error: validation.errors.join(', ') || 'Character details are incomplete',\n            focus: null\n        };\n    }\n    const initialCommands = initialCreationCommands({\n        identity,\n        state,\n        characterId,\n        characterType,\n        name: trimmedName,\n        age,\n        career: career ?? 'Scout',\n        drafted,\n        characteristics,\n        skills,\n        equipment,\n        credits,\n        notes\n    }).map((command) => command.type === 'UpdateCharacterSheet' ? { ...command, age } : command);\n    const finishCommands = playableCreationCommands(identity, characterId, creationOutcome).map((command, index) => sequenceCommandAt(command, state, initialCommands.length + index));\n    const pieceId = createLinkedPiece && board ? uniquePieceId(state, trimmedName) : null;\n    const pieceCommand = pieceId && board\n        ? [\n            sequenceCommandAt({\n                type: 'CreatePiece',\n                gameId: identity.gameId,\n                actorId: identity.actorId,\n                pieceId,\n                boardId: board.id,\n                characterId,\n                name: trimmedName,\n                imageAssetId: null,\n                x: Math.max(0, Math.min(board.width - 50, 160 + (existingPieceCount % 8) * 58)),\n                y: Math.max(0, Math.min(board.height - 50, 140 + Math.floor(existingPieceCount / 8) * 58)),\n                width: 50,\n                height: 50,\n                scale: 1\n            }, state, initialCommands.length + finishCommands.length)\n        ]\n        : [];\n    return {\n        ok: true,\n        commands: [...initialCommands, ...finishCommands, ...pieceCommand],\n        characterId,\n        pieceId\n    };\n};\nexport const planGeneratePlayableCharacterCommands = ({ identity, state, board, name, generated, createLinkedPiece, existingPieceCount, rng = Math.random }) => {\n    if (!state) {\n        return {\n            ok: false,\n            error: 'Open or create a room before generating a character',\n            focus: null\n        };\n    }\n    const preview = generated ?? generateCharacterPreview({ state, name, rng });\n    const plan = planCreatePlayableCharacterCommands({\n        identity,\n        state,\n        board,\n        name: preview.name,\n        characterType: 'PLAYER',\n        age: preview.age,\n        characteristics: preview.characteristics,\n        skills: preview.skills,\n        equipment: [],\n        credits: preview.credits,\n        notes: preview.notes,\n        createLinkedPiece,\n        existingPieceCount,\n        career: preview.career,\n        drafted: preview.drafted,\n        creationOutcome: preview.creationOutcome\n    });\n    if (!plan.ok)\n        return plan;\n    return {\n        ...plan,\n        generated: preview\n    };\n};\n"
export const CLIENT_CHARACTER_GENERATOR_PREVIEW_JS = "const characteristicDefinitions = [\n    { key: 'str', label: 'STR' },\n    { key: 'dex', label: 'DEX' },\n    { key: 'end', label: 'END' },\n    { key: 'int', label: 'INT' },\n    { key: 'edu', label: 'EDU' },\n    { key: 'soc', label: 'SOC' }\n];\nconst formatRollLabel = (label, roll) => `${label} (${roll})`;\nconst formatNullableRollLabel = (label, roll) => roll === null ? label : formatRollLabel(label, roll);\nexport const formatGeneratedCharacterCharacteristics = (characteristics) => characteristicDefinitions\n    .map(({ key, label }) => `${label} ${characteristics[key] ?? '-'}`)\n    .join('  ');\nexport const deriveGeneratedCharacterOutcomeLabels = (generated) => ({\n    qualification: generated.drafted\n        ? formatRollLabel('Drafted', generated.qualificationRoll)\n        : formatRollLabel('Qualified', generated.qualificationRoll),\n    survival: generated.survivalPassed\n        ? formatRollLabel('Survived', generated.survivalRoll)\n        : formatRollLabel('Mishap', generated.survivalRoll),\n    commission: generated.commissionPassed === null\n        ? null\n        : formatNullableRollLabel(generated.commissionPassed ? 'Commissioned' : 'No commission', generated.commissionRoll),\n    advancement: generated.advancementPassed === null\n        ? null\n        : formatNullableRollLabel(generated.advancementPassed ? 'Advanced' : 'Held rank', generated.advancementRoll),\n    credits: `${generated.credits} credits`\n});\nexport const deriveGeneratedCharacterPreviewLines = (generated) => [\n    {\n        key: 'characteristics',\n        label: 'Characteristics',\n        value: formatGeneratedCharacterCharacteristics(generated.characteristics)\n    },\n    {\n        key: 'skills',\n        label: 'Skills',\n        value: generated.skills.length > 0 ? generated.skills.join(', ') : '-'\n    }\n];\nexport const deriveGeneratedCharacterPreviewChips = (generated) => {\n    const labels = deriveGeneratedCharacterOutcomeLabels(generated);\n    const chips = [\n        {\n            key: 'survival',\n            label: labels.survival,\n            tone: generated.survivalPassed ? 'success' : 'warning'\n        },\n        {\n            key: 'credits',\n            label: labels.credits,\n            tone: 'neutral'\n        },\n        {\n            key: 'qualification',\n            label: labels.qualification,\n            tone: generated.drafted ? 'warning' : 'success'\n        }\n    ];\n    if (labels.commission) {\n        chips.push({\n            key: 'commission',\n            label: labels.commission,\n            tone: generated.commissionPassed ? 'success' : 'neutral'\n        });\n    }\n    if (labels.advancement) {\n        chips.push({\n            key: 'advancement',\n            label: labels.advancement,\n            tone: generated.advancementPassed ? 'success' : 'neutral'\n        });\n    }\n    return chips;\n};\nexport const deriveGeneratedCharacterPreview = (generated) => {\n    if (!generated)\n        return null;\n    return {\n        title: generated.name,\n        subtitle: `${generated.career} / Age ${generated.age}`,\n        lines: deriveGeneratedCharacterPreviewLines(generated),\n        chips: deriveGeneratedCharacterPreviewChips(generated),\n        canAccept: true\n    };\n};\n"
export const CLIENT_CHARACTER_SHEET_CONTROLLER_JS = "import { characterSheetEmptyLabels, characterSheetTitle, characteristicRows, characterSkills as deriveCharacterSkills, equipmentDisplayItems, selectedCharacter as selectCharacter, skillsFromText, skillRollReason } from './character-sheet-view.js';\nconst characterSheetPatchTargetId = (target) => typeof target === 'string' ? target : target.characterId || target.id || null;\nexport const nullableNumberFromValue = (value) => {\n    const trimmed = value.trim();\n    if (!trimmed)\n        return null;\n    const number = Number.parseInt(trimmed, 10);\n    return Number.isFinite(number) ? number : null;\n};\nexport const createCharacterSheetController = ({ elements, document: documentApi = document, getSelectedPiece, getSelectedBoard, getCharacterState, getBoardDoorActions, sendPatch, setVisibility, setFreedom, rollSkill, getCharacterCreationActions, reportError }) => {\n    let sheetOpen = false;\n    let activeSheetTab = 'details';\n    const handleAsyncError = (task) => {\n        task.catch((error) => {\n            reportError(error instanceof Error ? error.message : String(error));\n        });\n    };\n    const sendCharacterSheetPatch = (target, patch) => {\n        const characterId = characterSheetPatchTargetId(target);\n        if (!characterId || Object.keys(patch).length === 0) {\n            return Promise.resolve();\n        }\n        return sendPatch(characterId, patch);\n    };\n    const sheetRow = (label, value) => {\n        const row = documentApi.createElement('div');\n        row.className = 'sheet-row';\n        const labelEl = documentApi.createElement('span');\n        labelEl.className = 'sheet-label';\n        labelEl.textContent = label;\n        const valueEl = documentApi.createElement('span');\n        valueEl.className = 'sheet-value';\n        valueEl.textContent = value;\n        row.append(labelEl, valueEl);\n        return row;\n    };\n    const emptySheetText = (text) => {\n        const empty = documentApi.createElement('p');\n        empty.className = 'sheet-empty';\n        empty.textContent = text;\n        return empty;\n    };\n    const sheetSectionTitle = (text) => {\n        const title = documentApi.createElement('h3');\n        title.className = 'sheet-section-title';\n        title.textContent = text;\n        return title;\n    };\n    const sheetNotePreview = (text) => {\n        const preview = documentApi.createElement('p');\n        preview.className = 'sheet-note-preview';\n        preview.textContent = text || 'No notes';\n        return preview;\n    };\n    const statStrip = (character) => {\n        const stats = documentApi.createElement('div');\n        stats.className = 'stat-strip';\n        for (const { label, value } of characteristicRows(character)) {\n            const stat = documentApi.createElement('div');\n            stat.className = 'stat';\n            const name = documentApi.createElement('b');\n            name.textContent = label;\n            const number = documentApi.createElement('span');\n            number.textContent = value;\n            stat.append(name, number);\n            stats.append(stat);\n        }\n        return stats;\n    };\n    const nullableNumberFromInput = (input) => nullableNumberFromValue(input.value);\n    const editableDetailsForm = (piece, character) => {\n        if (!piece?.characterId || !character)\n            return statStrip(character);\n        const form = documentApi.createElement('div');\n        form.className = 'sheet-edit-form';\n        const line = documentApi.createElement('div');\n        line.className = 'sheet-edit-line';\n        const ageLabel = documentApi.createElement('label');\n        ageLabel.textContent = 'Age';\n        const ageInput = documentApi.createElement('input');\n        ageInput.name = 'age';\n        ageInput.inputMode = 'numeric';\n        ageInput.autocomplete = 'off';\n        ageInput.value = character.age == null ? '' : String(character.age);\n        ageLabel.append(ageInput);\n        const save = documentApi.createElement('button');\n        save.type = 'button';\n        save.textContent = 'Save';\n        line.append(ageLabel, save);\n        const statFields = documentApi.createElement('div');\n        statFields.className = 'sheet-stat-edit';\n        const inputs = {};\n        for (const { label, key, inputValue } of characteristicRows(character)) {\n            const field = documentApi.createElement('label');\n            field.textContent = label;\n            const input = documentApi.createElement('input');\n            input.name = key;\n            input.inputMode = 'numeric';\n            input.autocomplete = 'off';\n            input.value = inputValue;\n            inputs[key] = input;\n            field.append(input);\n            statFields.append(field);\n        }\n        save.addEventListener('click', () => {\n            handleAsyncError(sendCharacterSheetPatch({ characterId: piece.characterId }, {\n                age: nullableNumberFromInput(ageInput),\n                characteristics: {\n                    str: nullableNumberFromInput(inputs.str),\n                    dex: nullableNumberFromInput(inputs.dex),\n                    end: nullableNumberFromInput(inputs.end),\n                    int: nullableNumberFromInput(inputs.int),\n                    edu: nullableNumberFromInput(inputs.edu),\n                    soc: nullableNumberFromInput(inputs.soc)\n                }\n            }));\n        });\n        form.append(line, statFields);\n        return form;\n    };\n    const skillChips = (skills) => {\n        const chips = documentApi.createElement('div');\n        chips.className = 'chip-list';\n        for (const label of skills) {\n            const chip = documentApi.createElement('span');\n            chip.textContent = label;\n            chips.append(chip);\n        }\n        return chips;\n    };\n    const visibilityActions = (piece) => {\n        const actions = documentApi.createElement('div');\n        actions.className = 'sheet-actions';\n        for (const visibility of ['HIDDEN', 'PREVIEW', 'VISIBLE']) {\n            const button = documentApi.createElement('button');\n            button.type = 'button';\n            button.textContent =\n                visibility === 'HIDDEN' ? 'Hide' : visibility.toLowerCase();\n            button.className = piece.visibility === visibility ? 'active' : '';\n            button.addEventListener('click', () => {\n                handleAsyncError(setVisibility(piece, visibility));\n            });\n            actions.append(button);\n        }\n        return actions;\n    };\n    const freedomActions = (piece) => {\n        const actions = documentApi.createElement('div');\n        actions.className = 'sheet-actions';\n        for (const freedom of ['LOCKED', 'UNLOCKED', 'SHARE']) {\n            const button = documentApi.createElement('button');\n            button.type = 'button';\n            button.textContent = freedom === 'LOCKED' ? 'Lock' : freedom.toLowerCase();\n            button.className = piece.freedom === freedom ? 'active' : '';\n            button.addEventListener('click', () => {\n                handleAsyncError(setFreedom(piece, freedom));\n            });\n            actions.append(button);\n        }\n        return actions;\n    };\n    const appendDoorActions = (body) => {\n        const doorActions = getBoardDoorActions().actions;\n        if (doorActions)\n            body.append(sheetSectionTitle('Doors'), doorActions);\n    };\n    const appendCreationActions = (body, character) => {\n        const creationActions = getCharacterCreationActions?.(character);\n        if (!creationActions)\n            return;\n        body.append(sheetSectionTitle(creationActions.title), sheetRow('Status', creationActions.status), emptySheetText(creationActions.summary));\n        if (creationActions.actions)\n            body.append(creationActions.actions);\n    };\n    const creationRows = (creation) => {\n        if (!creation)\n            return [sheetRow('Creation', 'Not started')];\n        const rows = [\n            sheetRow('Creation', creation.state.status.replaceAll('_', ' ')),\n            sheetRow('Terms', String(creation.terms.length)),\n            sheetRow('Complete', creation.creationComplete ? 'Yes' : 'No')\n        ];\n        const career = creation.careers.at(-1);\n        if (career)\n            rows.splice(2, 0, sheetRow('Career', career.name));\n        return rows;\n    };\n    const skillEditor = (piece, character, skills) => {\n        if (!piece.characterId || !character)\n            return null;\n        const form = documentApi.createElement('div');\n        form.className = 'sheet-skill-editor';\n        const label = documentApi.createElement('label');\n        label.textContent = 'Skills';\n        const textarea = documentApi.createElement('textarea');\n        textarea.value = skills.join('\\n');\n        textarea.placeholder = 'Vacc Suit-0\\\\nGun Combat-0';\n        textarea.spellcheck = false;\n        const save = documentApi.createElement('button');\n        save.type = 'button';\n        save.textContent = 'Save skills';\n        save.addEventListener('click', () => {\n            handleAsyncError(sendCharacterSheetPatch({ characterId: piece.characterId }, { skills: skillsFromText(textarea.value) }));\n        });\n        label.append(textarea);\n        form.append(label, save);\n        return form;\n    };\n    const renderDetailsTab = (body, piece, character) => {\n        if (!character) {\n            body.append(sheetSectionTitle('Token'), sheetRow('Name', piece.name), sheetRow('Position', `${Math.round(piece.x)}, ${Math.round(piece.y)}`), sheetRow('Visibility', piece.visibility), visibilityActions(piece), sheetRow('Move', piece.freedom), freedomActions(piece), emptySheetText(characterSheetEmptyLabels.noLinkedCharacterSheet));\n            appendDoorActions(body);\n            return;\n        }\n        body.append(sheetSectionTitle('Profile'), sheetRow('Type', character.type || 'PLAYER'), sheetRow('Age', character.age == null ? '-' : String(character.age)), statStrip(character), ...creationRows(character.creation), sheetSectionTitle('Token'), sheetRow('Position', `${Math.round(piece.x)}, ${Math.round(piece.y)}`), sheetRow('Visibility', piece.visibility), visibilityActions(piece), sheetRow('Move', piece.freedom), freedomActions(piece), sheetSectionTitle('Edit'), editableDetailsForm(piece, character), sheetSectionTitle('Skills'), skillChips(deriveCharacterSkills(character)));\n        appendDoorActions(body);\n    };\n    const renderActionTab = (body, piece, character) => {\n        appendCreationActions(body, character);\n        const skills = deriveCharacterSkills(character);\n        if (skills.length === 0) {\n            body.append(emptySheetText(characterSheetEmptyLabels.noTrainedSkills));\n            return;\n        }\n        const actions = documentApi.createElement('div');\n        actions.className = 'sheet-skill-actions';\n        body.append(sheetSectionTitle('Roll'));\n        for (const skill of skills) {\n            const button = documentApi.createElement('button');\n            button.type = 'button';\n            button.textContent = skill;\n            button.addEventListener('click', () => {\n                handleAsyncError(rollSkill(piece, character, skill, skillRollReason(piece, character, skill)));\n            });\n            actions.append(button);\n        }\n        const editor = skillEditor(piece, character, skills);\n        if (editor)\n            body.append(actions, sheetSectionTitle('Edit Skills'), editor);\n        else\n            body.append(actions);\n    };\n    const itemsEditor = (character) => {\n        if (!character)\n            return null;\n        const equipment = Array.isArray(character.equipment)\n            ? character.equipment\n            : [];\n        const form = documentApi.createElement('div');\n        form.className = 'sheet-items-editor';\n        const creditsLabel = documentApi.createElement('label');\n        creditsLabel.textContent = 'Credits';\n        const creditsInput = documentApi.createElement('input');\n        creditsInput.name = 'credits';\n        creditsInput.inputMode = 'numeric';\n        creditsInput.autocomplete = 'off';\n        creditsInput.value =\n            character.credits == null ? '0' : String(character.credits);\n        creditsLabel.append(creditsInput);\n        const equipmentRows = documentApi.createElement('div');\n        equipmentRows.className = 'sheet-equipment-rows';\n        const rowInputs = [];\n        const appendEquipmentRow = (item) => {\n            const row = documentApi.createElement('div');\n            row.className = 'sheet-equipment-row';\n            const name = documentApi.createElement('input');\n            name.name = 'equipmentName';\n            name.autocomplete = 'off';\n            name.placeholder = 'Item';\n            name.value = item?.name || '';\n            const quantity = documentApi.createElement('input');\n            quantity.name = 'equipmentQuantity';\n            quantity.inputMode = 'numeric';\n            quantity.autocomplete = 'off';\n            quantity.placeholder = 'Qty';\n            quantity.value =\n                item?.quantity == null ? '1' : String(Math.max(1, item.quantity));\n            const notes = documentApi.createElement('input');\n            notes.name = 'equipmentNotes';\n            notes.autocomplete = 'off';\n            notes.placeholder = 'Notes';\n            notes.value = item?.notes || '';\n            rowInputs.push({ name, quantity, notes });\n            row.append(name, quantity, notes);\n            equipmentRows.append(row);\n        };\n        for (const item of equipment)\n            appendEquipmentRow(item);\n        if (equipment.length === 0)\n            appendEquipmentRow();\n        const addItem = documentApi.createElement('button');\n        addItem.type = 'button';\n        addItem.textContent = 'Add item';\n        addItem.addEventListener('click', () => {\n            appendEquipmentRow();\n        });\n        const save = documentApi.createElement('button');\n        save.type = 'button';\n        save.textContent = 'Save items';\n        save.addEventListener('click', () => {\n            const nextEquipment = rowInputs\n                .map(({ name, quantity, notes }) => ({\n                name: name.value.trim(),\n                quantity: nullableNumberFromInput(quantity) ?? 1,\n                notes: notes.value.trim()\n            }))\n                .filter((item) => item.name.length > 0);\n            handleAsyncError(sendCharacterSheetPatch({ characterId: character.id }, {\n                credits: nullableNumberFromInput(creditsInput) ?? 0,\n                equipment: nextEquipment\n            }));\n        });\n        form.append(creditsLabel, equipmentRows, addItem, save);\n        return form;\n    };\n    const renderItemsTab = (body, character) => {\n        body.append(sheetSectionTitle('Resources'), sheetRow('Credits', character?.credits == null ? '-' : String(character.credits)));\n        const equipment = Array.isArray(character?.equipment)\n            ? character.equipment\n            : [];\n        if (equipment.length === 0) {\n            body.append(emptySheetText(characterSheetEmptyLabels.noEquipmentListed));\n            const editor = itemsEditor(character);\n            if (editor)\n                body.append(sheetSectionTitle('Edit Items'), editor);\n            return;\n        }\n        const list = documentApi.createElement('div');\n        list.className = 'item-list';\n        body.append(sheetSectionTitle('Equipment'));\n        for (const item of equipmentDisplayItems(equipment)) {\n            const row = documentApi.createElement('div');\n            row.className = 'item-row';\n            const name = documentApi.createElement('span');\n            name.className = 'item-name';\n            name.textContent = item.name;\n            const meta = documentApi.createElement('span');\n            meta.className = 'item-meta';\n            meta.textContent = item.meta;\n            row.append(name, meta);\n            if (item.notes) {\n                const note = documentApi.createElement('span');\n                note.className = 'item-note';\n                note.textContent = item.notes;\n                row.append(note);\n            }\n            list.append(row);\n        }\n        const editor = itemsEditor(character);\n        if (editor)\n            body.append(list, sheetSectionTitle('Edit Items'), editor);\n        else\n            body.append(list);\n    };\n    const renderNotesTab = (body, piece, character) => {\n        if (!piece.characterId || !character) {\n            body.append(sheetSectionTitle('Notes'), emptySheetText(character?.notes || characterSheetEmptyLabels.noNotes));\n            return;\n        }\n        const form = documentApi.createElement('div');\n        form.className = 'sheet-notes-form';\n        const textarea = documentApi.createElement('textarea');\n        textarea.value = character.notes || '';\n        textarea.placeholder = 'No notes';\n        textarea.spellcheck = true;\n        const save = documentApi.createElement('button');\n        save.type = 'button';\n        save.textContent = 'Save';\n        save.addEventListener('click', () => {\n            handleAsyncError(sendCharacterSheetPatch({ characterId: piece.characterId }, { notes: textarea.value }));\n        });\n        form.append(textarea, save);\n        body.append(sheetSectionTitle('Current Notes'), sheetNotePreview(character.notes), sheetSectionTitle('Edit Notes'), form);\n    };\n    const render = () => {\n        const piece = getSelectedPiece();\n        const state = getCharacterState();\n        const character = selectCharacter(state, piece);\n        elements.sheetName.textContent = characterSheetTitle(piece, character);\n        for (const tab of elements.sheetTabs) {\n            tab.classList.toggle('active', tab.dataset.sheetTab === activeSheetTab);\n        }\n        const body = documentApi.createElement('div');\n        body.className = 'sheet-grid';\n        if (!piece) {\n            body.append(sheetRow('Status', characterSheetEmptyLabels.noActiveToken));\n            body.append(sheetRow('Board', getSelectedBoard()?.name || 'None'));\n            appendDoorActions(body);\n            elements.sheetBody.replaceChildren(body);\n            return;\n        }\n        if (activeSheetTab === 'action')\n            renderActionTab(body, piece, character);\n        else if (activeSheetTab === 'items')\n            renderItemsTab(body, character);\n        else if (activeSheetTab === 'notes')\n            renderNotesTab(body, piece, character);\n        else\n            renderDetailsTab(body, piece, character);\n        elements.sheetBody.replaceChildren(body);\n    };\n    const setOpen = (open) => {\n        sheetOpen = open;\n        elements.sheet.classList.toggle('open', sheetOpen);\n    };\n    return {\n        isOpen: () => sheetOpen,\n        setOpen,\n        toggleOpen: () => setOpen(!sheetOpen),\n        render,\n        selectTab: (tab) => {\n            if (tab === 'action' ||\n                tab === 'items' ||\n                tab === 'notes' ||\n                tab === 'details') {\n                activeSheetTab = tab;\n            }\n            else {\n                activeSheetTab = 'details';\n            }\n            render();\n        }\n    };\n};\n"
export const CLIENT_CHARACTER_SHEET_VIEW_JS = "const characteristicDefinitions = [\n    { key: 'str', label: 'Str', fallback: 7 },\n    { key: 'dex', label: 'Dex', fallback: 8 },\n    { key: 'end', label: 'End', fallback: 8 },\n    { key: 'int', label: 'Int', fallback: 7 },\n    { key: 'edu', label: 'Edu', fallback: 9 },\n    { key: 'soc', label: 'Soc', fallback: 6 }\n];\nexport const characterSheetTabLabels = {\n    details: 'Details',\n    action: 'Action',\n    items: 'Items',\n    notes: 'Notes'\n};\nexport const characterSheetEmptyLabels = {\n    noActiveToken: 'No active token',\n    noLinkedCharacterSheet: 'No linked character sheet',\n    noTrainedSkills: 'No trained skills',\n    noEquipmentListed: 'No equipment listed',\n    noNotes: 'No notes'\n};\nexport const selectedCharacter = (state, piece) => {\n    if (!piece?.characterId)\n        return null;\n    return state?.characters[piece.characterId] ?? null;\n};\nexport const characterSheetTitle = (piece, character) => character?.name || piece?.name || 'No piece';\nexport const characteristicRows = (character) => {\n    const values = character?.characteristics;\n    return characteristicDefinitions.map(({ key, label, fallback }) => {\n        const value = values?.[key] ?? fallback;\n        return {\n            key,\n            label,\n            value: String(value),\n            inputValue: values?.[key] == null ? '' : String(values[key])\n        };\n    });\n};\nexport const characterSkills = (character) => {\n    if (character && Array.isArray(character.skills)) {\n        return character.skills\n            .filter((skill) => typeof skill === 'string' && skill.trim())\n            .map((skill) => skill.trim());\n    }\n    if (character)\n        return [];\n    return ['Vacc Suit-0', 'Gun Combat-0', 'Mechanic-0', 'Recon-0'];\n};\nexport const skillsFromText = (value) => value\n    .split(/[\\n,]/)\n    .map((skill) => skill.trim())\n    .filter(Boolean);\nexport const skillRollReason = (piece, character, skill) => `${character?.name || piece.name}: ${skill}`;\nconst equipmentName = (item) => item.Name || item.name || 'Item';\nconst equipmentQuantity = (item) => item.Quantity ?? item.quantity ?? 1;\nconst equipmentNotes = (item) => item.notes || item.Notes || '';\nconst equipmentCarried = (item) => item.Carried ?? item.carried;\nexport const equipmentDisplayItems = (equipment) => (Array.isArray(equipment) ? equipment : []).map((item) => {\n    const source = item;\n    const quantity = equipmentQuantity(source);\n    const carried = equipmentCarried(source);\n    return {\n        name: equipmentName(source),\n        quantity,\n        notes: equipmentNotes(source),\n        carried,\n        meta: 'x' +\n            quantity +\n            (carried === undefined ? '' : carried ? ' carried' : ' stowed')\n    };\n});\nexport const equipmentText = (equipment) => equipmentDisplayItems(equipment)\n    .map((item) => [item.name, item.quantity, item.notes].join(' | '))\n    .join('\\n');\nexport const equipmentFromText = (value) => value\n    .split('\\n')\n    .map((line) => {\n    const [name = '', quantity = '1', ...notes] = line\n        .split('|')\n        .map((part) => part.trim());\n    if (!name)\n        return null;\n    const parsedQuantity = Number.parseInt(quantity, 10);\n    return {\n        name,\n        quantity: Number.isFinite(parsedQuantity) ? parsedQuantity : 1,\n        notes: notes.join(' | ')\n    };\n})\n    .filter((item) => item !== null);\n"
export const CLIENT_CHARACTER_CREATION_FLOW_JS = "import { buildSequencedCommand } from '../game-commands.js';\nconst CHARACTER_CREATION_STEPS = [\n    'basics',\n    'characteristics',\n    'skills',\n    'equipment',\n    'review'\n];\nconst CHARACTERISTIC_KEYS = [\n    'str',\n    'dex',\n    'end',\n    'int',\n    'edu',\n    'soc'\n];\nconst emptyCharacteristics = () => ({\n    str: null,\n    dex: null,\n    end: null,\n    int: null,\n    edu: null,\n    soc: null\n});\nconst cloneEquipment = (equipment) => equipment.map((item) => ({\n    name: item.name,\n    quantity: item.quantity,\n    notes: item.notes\n}));\nconst normalizeSkillList = (skills) => {\n    const normalized = [];\n    const seen = new Set();\n    for (const rawSkill of skills) {\n        const skill = rawSkill.trim();\n        const key = skill.toLowerCase();\n        if (!skill || seen.has(key))\n            continue;\n        normalized.push(skill);\n        seen.add(key);\n    }\n    return normalized;\n};\nconst normalizeEquipmentList = (equipment) => {\n    const normalized = [];\n    for (const item of equipment) {\n        const name = item.name.trim();\n        if (!name)\n            continue;\n        normalized.push({\n            name,\n            quantity: Number.isFinite(item.quantity) && item.quantity > 0 ? item.quantity : 1,\n            notes: item.notes.trim()\n        });\n    }\n    return normalized;\n};\nconst isFiniteNonNegativeNumber = (value) => Number.isFinite(value) && value >= 0;\nconst stepIndex = (step) => CHARACTER_CREATION_STEPS.indexOf(step);\nconst sequenceCommandAt = (command, state, offset) => {\n    if (!state ||\n        command.expectedSeq !== undefined ||\n        command.type === 'CreateGame') {\n        return command;\n    }\n    return {\n        ...command,\n        expectedSeq: state.eventSeq + offset\n    };\n};\nconst validateBasics = (draft) => {\n    const errors = [];\n    if (!draft.name.trim())\n        errors.push('Name is required');\n    if (draft.age !== null && !isFiniteNonNegativeNumber(draft.age)) {\n        errors.push('Age must be a non-negative number');\n    }\n    return errors;\n};\nconst validateCharacteristics = (draft) => {\n    const errors = [];\n    for (const key of CHARACTERISTIC_KEYS) {\n        const value = draft.characteristics[key];\n        if (value === null) {\n            errors.push(`${key.toUpperCase()} is required`);\n        }\n        else if (!Number.isFinite(value)) {\n            errors.push(`${key.toUpperCase()} must be a finite number`);\n        }\n    }\n    return errors;\n};\nconst validateSkills = (draft) => draft.skills.length === 0 ? ['At least one skill is required'] : [];\nconst validateEquipment = (draft) => {\n    const errors = [];\n    if (!isFiniteNonNegativeNumber(draft.credits)) {\n        errors.push('Credits must be a non-negative number');\n    }\n    for (const [index, item] of draft.equipment.entries()) {\n        if (!item.name.trim())\n            errors.push(`Equipment ${index + 1} needs a name`);\n        if (!Number.isFinite(item.quantity) || item.quantity <= 0) {\n            errors.push(`Equipment ${index + 1} quantity must be positive`);\n        }\n    }\n    return errors;\n};\nconst validationErrorsForStep = (step, draft) => {\n    switch (step) {\n        case 'basics':\n            return validateBasics(draft);\n        case 'characteristics':\n            return validateCharacteristics(draft);\n        case 'skills':\n            return validateSkills(draft);\n        case 'equipment':\n            return validateEquipment(draft);\n        case 'review':\n            return [\n                ...validateBasics(draft),\n                ...validateCharacteristics(draft),\n                ...validateSkills(draft),\n                ...validateEquipment(draft)\n            ];\n        default: {\n            const exhaustive = step;\n            return [`Unsupported step ${exhaustive}`];\n        }\n    }\n};\nexport const characterCreationSteps = () => [\n    ...CHARACTER_CREATION_STEPS\n];\nexport const createInitialCharacterDraft = (characterId, overrides = {}) => ({\n    characterId,\n    characterType: overrides.characterType ?? 'PLAYER',\n    name: overrides.name ?? '',\n    age: overrides.age ?? null,\n    characteristics: {\n        ...emptyCharacteristics(),\n        ...(overrides.characteristics ?? {})\n    },\n    skills: normalizeSkillList(overrides.skills ?? []),\n    equipment: normalizeEquipmentList(overrides.equipment ?? []),\n    credits: overrides.credits ?? 0,\n    notes: overrides.notes ?? ''\n});\nexport const createCharacterCreationFlow = (characterId, overrides = {}) => ({\n    step: 'basics',\n    draft: createInitialCharacterDraft(characterId, overrides)\n});\nexport const updateCharacterCreationDraft = (draft, patch) => ({\n    characterId: patch.characterId ?? draft.characterId,\n    characterType: patch.characterType ?? draft.characterType,\n    name: patch.name ?? draft.name,\n    age: patch.age ?? draft.age,\n    credits: patch.credits ?? draft.credits,\n    notes: patch.notes ?? draft.notes,\n    characteristics: {\n        ...draft.characteristics,\n        ...(patch.characteristics ?? {})\n    },\n    skills: patch.skills === undefined\n        ? [...draft.skills]\n        : normalizeSkillList(patch.skills),\n    equipment: patch.equipment === undefined\n        ? cloneEquipment(draft.equipment)\n        : normalizeEquipmentList(patch.equipment)\n});\nexport const updateCharacterCreationFields = (flow, patch) => ({\n    ...flow,\n    draft: updateCharacterCreationDraft(flow.draft, patch)\n});\nexport const validateCurrentCharacterCreationStep = (flow) => {\n    const errors = validationErrorsForStep(flow.step, flow.draft);\n    return {\n        ok: errors.length === 0,\n        step: flow.step,\n        errors\n    };\n};\nexport const advanceCharacterCreationStep = (flow) => {\n    const validation = validateCurrentCharacterCreationStep(flow);\n    if (!validation.ok)\n        return flow;\n    const nextIndex = Math.min(stepIndex(flow.step) + 1, CHARACTER_CREATION_STEPS.length - 1);\n    return {\n        ...flow,\n        step: CHARACTER_CREATION_STEPS[nextIndex]\n    };\n};\nexport const backCharacterCreationStep = (flow) => {\n    const previousIndex = Math.max(stepIndex(flow.step) - 1, 0);\n    return {\n        ...flow,\n        step: CHARACTER_CREATION_STEPS[previousIndex]\n    };\n};\nexport const deriveCreateCharacterCommand = (draft, { identity, state = null }) => buildSequencedCommand({\n    type: 'CreateCharacter',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    characterId: draft.characterId,\n    characterType: draft.characterType,\n    name: draft.name.trim()\n}, state);\nexport const deriveStartCharacterCreationCommand = (draft, { identity, state = null }) => buildSequencedCommand({\n    type: 'StartCharacterCreation',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    characterId: draft.characterId\n}, state);\nexport const deriveStartCharacterCareerTermCommand = (draft, { identity, state = null }) => buildSequencedCommand({\n    type: 'StartCharacterCareerTerm',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    characterId: draft.characterId,\n    career: 'Scout'\n}, state);\nconst initialCharacterCreationStateCommands = (draft, identity) => [\n    {\n        type: 'StartCharacterCreation',\n        gameId: identity.gameId,\n        actorId: identity.actorId,\n        characterId: draft.characterId\n    },\n    {\n        type: 'AdvanceCharacterCreation',\n        gameId: identity.gameId,\n        actorId: identity.actorId,\n        characterId: draft.characterId,\n        creationEvent: { type: 'SET_CHARACTERISTICS' }\n    },\n    {\n        type: 'AdvanceCharacterCreation',\n        gameId: identity.gameId,\n        actorId: identity.actorId,\n        characterId: draft.characterId,\n        creationEvent: { type: 'COMPLETE_HOMEWORLD' }\n    },\n    {\n        type: 'StartCharacterCareerTerm',\n        gameId: identity.gameId,\n        actorId: identity.actorId,\n        characterId: draft.characterId,\n        career: 'Scout'\n    },\n    {\n        type: 'AdvanceCharacterCreation',\n        gameId: identity.gameId,\n        actorId: identity.actorId,\n        characterId: draft.characterId,\n        creationEvent: {\n            type: 'SELECT_CAREER',\n            isNewCareer: true\n        }\n    }\n];\nexport const deriveInitialCharacterCreationStateCommands = (draft, { identity, state = null }) => {\n    if (!state)\n        return [];\n    return initialCharacterCreationStateCommands(draft, identity).map((command, index) => sequenceCommandAt(command, state, index));\n};\nexport const deriveCharacterSheetPatch = (draft) => ({\n    age: draft.age,\n    characteristics: { ...draft.characteristics },\n    skills: [...draft.skills],\n    equipment: cloneEquipment(draft.equipment),\n    credits: draft.credits,\n    notes: draft.notes\n});\nexport const deriveUpdateCharacterSheetCommand = (draft, { identity, state = null }) => buildSequencedCommand({\n    type: 'UpdateCharacterSheet',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    characterId: draft.characterId,\n    ...deriveCharacterSheetPatch(draft)\n}, state);\nexport const deriveCharacterCreationCommands = (flow, options) => {\n    const validation = {\n        ...validateCurrentCharacterCreationStep({\n            ...flow,\n            step: 'review'\n        })\n    };\n    if (!validation.ok)\n        return [];\n    if (!options.state)\n        return [];\n    const baseCommands = [\n        {\n            type: 'CreateCharacter',\n            gameId: options.identity.gameId,\n            actorId: options.identity.actorId,\n            characterId: flow.draft.characterId,\n            characterType: flow.draft.characterType,\n            name: flow.draft.name.trim()\n        },\n        ...initialCharacterCreationStateCommands(flow.draft, options.identity),\n        {\n            type: 'UpdateCharacterSheet',\n            gameId: options.identity.gameId,\n            actorId: options.identity.actorId,\n            characterId: flow.draft.characterId,\n            ...deriveCharacterSheetPatch(flow.draft)\n        }\n    ];\n    return baseCommands.map((command, index) => sequenceCommandAt(command, options.state ?? null, index));\n};\n"
export const CLIENT_CHARACTER_CREATION_VIEW_JS = "import { validateCurrentCharacterCreationStep } from './character-creation-flow.js';\nconst characteristicDefinitions = [\n    { key: 'str', label: 'Str' },\n    { key: 'dex', label: 'Dex' },\n    { key: 'end', label: 'End' },\n    { key: 'int', label: 'Int' },\n    { key: 'edu', label: 'Edu' },\n    { key: 'soc', label: 'Soc' }\n];\nexport const characterCreationStepLabels = {\n    basics: 'Basics',\n    characteristics: 'Characteristics',\n    skills: 'Skills',\n    equipment: 'Equipment',\n    review: 'Review'\n};\nexport const characterCreationPrimaryCtaLabels = {\n    basics: 'Continue to characteristics',\n    characteristics: 'Continue to skills',\n    skills: 'Continue to equipment',\n    equipment: 'Review character',\n    review: 'Create character'\n};\nexport const deriveCharacterCreationCtaLabels = (step) => ({\n    primary: characterCreationPrimaryCtaLabels[step],\n    secondary: step === 'basics' ? null : 'Back'\n});\nconst valueText = (value) => {\n    if (value === null || value === undefined)\n        return '';\n    return String(value);\n};\nconst parseOptionalNumber = (value) => {\n    if (value === undefined)\n        return undefined;\n    if (value === null)\n        return null;\n    const text = String(value).trim();\n    if (!text)\n        return null;\n    const parsed = Number(text);\n    return Number.isFinite(parsed) ? parsed : Number.NaN;\n};\nconst parseNumberWithDefault = (value, fallback) => {\n    if (value === undefined)\n        return undefined;\n    if (value === null)\n        return fallback;\n    const text = String(value).trim();\n    if (!text)\n        return fallback;\n    const parsed = Number(text);\n    return Number.isFinite(parsed) ? parsed : Number.NaN;\n};\nconst splitListText = (value) => value\n    .split(/[\\n,]/)\n    .map((part) => part.trim())\n    .filter(Boolean);\nconst parseEquipmentText = (value) => value\n    .split('\\n')\n    .map((line) => {\n    const [name = '', quantity = '1', ...notes] = line\n        .split('|')\n        .map((part) => part.trim());\n    if (!name)\n        return null;\n    const parsedQuantity = Number.parseInt(quantity, 10);\n    return {\n        name,\n        quantity: Number.isFinite(parsedQuantity) ? parsedQuantity : 1,\n        notes: notes.join(' | ')\n    };\n})\n    .filter((item) => item !== null);\nconst validationForStep = (flow, step = flow.step) => validateCurrentCharacterCreationStep({\n    ...flow,\n    step\n});\nconst fieldErrors = (errors, key, characteristicKey) => errors.filter((error) => {\n    if (key === 'name')\n        return error.startsWith('Name ');\n    if (key === 'age')\n        return error.startsWith('Age ');\n    if (key === 'skills')\n        return error.startsWith('At least one skill');\n    if (key === 'credits')\n        return error.startsWith('Credits ');\n    if (key === 'equipment')\n        return error.startsWith('Equipment ');\n    if (characteristicKey) {\n        return error.startsWith(`${characteristicKey.toUpperCase()} `);\n    }\n    return false;\n});\nexport const deriveCharacterCreationValidationSummary = (flow, step = flow.step) => {\n    const validation = validationForStep(flow, step);\n    const errorCount = validation.errors.length;\n    return {\n        ok: validation.ok,\n        step: validation.step,\n        errors: [...validation.errors],\n        errorCount,\n        message: validation.ok\n            ? 'Ready to continue'\n            : `${errorCount} ${errorCount === 1 ? 'issue' : 'issues'} to fix`\n    };\n};\nexport const deriveCharacterCreationFieldViewModels = (flow, step = flow.step) => {\n    const validation = validationForStep(flow, step);\n    const { draft } = flow;\n    switch (step) {\n        case 'basics':\n            return [\n                {\n                    key: 'name',\n                    label: 'Name',\n                    kind: 'text',\n                    step,\n                    value: draft.name,\n                    required: true,\n                    errors: fieldErrors(validation.errors, 'name')\n                },\n                {\n                    key: 'age',\n                    label: 'Age',\n                    kind: 'number',\n                    step,\n                    value: valueText(draft.age),\n                    required: false,\n                    errors: fieldErrors(validation.errors, 'age')\n                },\n                {\n                    key: 'characterType',\n                    label: 'Type',\n                    kind: 'select',\n                    step,\n                    value: draft.characterType,\n                    required: true,\n                    errors: []\n                }\n            ];\n        case 'characteristics':\n            return characteristicDefinitions.map(({ key, label }) => ({\n                key,\n                label,\n                kind: 'number',\n                step,\n                value: valueText(draft.characteristics[key]),\n                required: true,\n                errors: fieldErrors(validation.errors, key, key)\n            }));\n        case 'skills':\n            return [\n                {\n                    key: 'skills',\n                    label: 'Skills',\n                    kind: 'textarea',\n                    step,\n                    value: draft.skills.join('\\n'),\n                    required: true,\n                    errors: fieldErrors(validation.errors, 'skills')\n                }\n            ];\n        case 'equipment':\n            return [\n                {\n                    key: 'equipment',\n                    label: 'Equipment',\n                    kind: 'textarea',\n                    step,\n                    value: equipmentText(draft.equipment),\n                    required: false,\n                    errors: fieldErrors(validation.errors, 'equipment')\n                },\n                {\n                    key: 'credits',\n                    label: 'Credits',\n                    kind: 'number',\n                    step,\n                    value: valueText(draft.credits),\n                    required: false,\n                    errors: fieldErrors(validation.errors, 'credits')\n                },\n                {\n                    key: 'notes',\n                    label: 'Notes',\n                    kind: 'textarea',\n                    step,\n                    value: draft.notes,\n                    required: false,\n                    errors: []\n                }\n            ];\n        case 'review':\n            return [];\n        default: {\n            const exhaustive = step;\n            return exhaustive;\n        }\n    }\n};\nexport const parseCharacterCreationDraftPatch = (values) => {\n    const patch = {};\n    if (values.name !== undefined)\n        patch.name = valueText(values.name);\n    if (values.characterType !== undefined) {\n        const characterType = valueText(values.characterType);\n        if (characterType === 'PLAYER' ||\n            characterType === 'NPC' ||\n            characterType === 'ANIMAL' ||\n            characterType === 'ROBOT') {\n            patch.characterType = characterType;\n        }\n    }\n    if (values.age !== undefined)\n        patch.age = parseOptionalNumber(values.age);\n    if (values.credits !== undefined) {\n        patch.credits = parseNumberWithDefault(values.credits, 0);\n    }\n    if (values.notes !== undefined)\n        patch.notes = valueText(values.notes);\n    if (values.skills !== undefined) {\n        patch.skills = splitListText(valueText(values.skills));\n    }\n    if (values.equipment !== undefined) {\n        patch.equipment = parseEquipmentText(valueText(values.equipment));\n    }\n    const characteristics = {};\n    for (const { key } of characteristicDefinitions) {\n        const value = Object.hasOwn(values, key)\n            ? values[key]\n            : values[`characteristics.${key}`];\n        if (value !== undefined)\n            characteristics[key] = parseOptionalNumber(value);\n    }\n    if (Object.keys(characteristics).length > 0) {\n        patch.characteristics = characteristics;\n    }\n    return patch;\n};\nexport const equipmentText = (equipment) => equipment\n    .map((item) => [item.name, item.quantity, item.notes].join(' | '))\n    .join('\\n');\nconst itemValue = (value) => value === null || value === '' ? 'Not set' : String(value);\nexport const deriveCharacterCreationReviewSummary = (flow) => {\n    const { draft } = flow;\n    const skills = draft.skills.length > 0 ? draft.skills.join(', ') : 'Not set';\n    const equipment = draft.equipment.length > 0\n        ? draft.equipment\n            .map((item) => `${item.name} x${item.quantity}`)\n            .join(', ')\n        : 'None';\n    return {\n        title: draft.name.trim() || 'Unnamed character',\n        subtitle: draft.characterType,\n        sections: [\n            {\n                key: 'basics',\n                label: characterCreationStepLabels.basics,\n                items: [\n                    { label: 'Name', value: itemValue(draft.name.trim()) },\n                    { label: 'Type', value: draft.characterType },\n                    { label: 'Age', value: itemValue(draft.age) }\n                ]\n            },\n            {\n                key: 'characteristics',\n                label: characterCreationStepLabels.characteristics,\n                items: characteristicDefinitions.map(({ key, label }) => ({\n                    label,\n                    value: itemValue(draft.characteristics[key])\n                }))\n            },\n            {\n                key: 'skills',\n                label: characterCreationStepLabels.skills,\n                items: [{ label: 'Skills', value: skills }]\n            },\n            {\n                key: 'equipment',\n                label: characterCreationStepLabels.equipment,\n                items: [\n                    { label: 'Equipment', value: equipment },\n                    { label: 'Credits', value: itemValue(draft.credits) },\n                    { label: 'Notes', value: itemValue(draft.notes.trim()) }\n                ]\n            }\n        ]\n    };\n};\n"
export const CLIENT_DICE_OVERLAY_JS = "import { deriveDicePipSlots, deriveDiceRollTiming, deriveDieFaces, deriveDieTilt } from '../dice.js';\nexport const deriveFaceValueContent = (value) => {\n    const slots = deriveDicePipSlots(value);\n    return slots\n        ? { kind: 'pips', slots }\n        : { kind: 'numeric', label: String(value) };\n};\nexport const appendFaceValue = (face, value) => {\n    const content = deriveFaceValueContent(value);\n    if (content.kind === 'numeric') {\n        face.classList.add('numeric');\n        face.textContent = content.label;\n        return;\n    }\n    for (const slot of content.slots) {\n        const pip = document.createElement('span');\n        pip.className = `pip pip-${slot}`;\n        face.append(pip);\n    }\n};\nexport const buildDie = (value, index) => {\n    const die = document.createElement('div');\n    die.className = 'die rolling';\n    die.setAttribute('aria-label', `Die result ${value}`);\n    const tilt = deriveDieTilt(index);\n    die.style.setProperty('--die-tilt-x', tilt.x);\n    die.style.setProperty('--die-tilt-y', tilt.y);\n    die.style.setProperty('--die-tilt-z', tilt.z);\n    for (const { name, value: label } of deriveDieFaces(value)) {\n        const face = document.createElement('div');\n        face.className = `face ${name}`;\n        face.setAttribute('aria-hidden', 'true');\n        appendFaceValue(face, label);\n        die.append(face);\n    }\n    return die;\n};\nexport const animateRoll = ({ roll, overlay, stage, hideTimer }) => {\n    if (hideTimer)\n        window.clearTimeout(hideTimer);\n    overlay.classList.add('visible');\n    const timing = deriveDiceRollTiming({\n        revealAt: roll.revealAt,\n        nowMs: Date.now()\n    });\n    const row = document.createElement('div');\n    row.className = 'dice-row';\n    roll.rolls.forEach((value, index) => {\n        const die = buildDie(value, index);\n        die.style.animationDuration = `${timing.rollDurationMs}ms`;\n        row.append(die);\n    });\n    const total = document.createElement('div');\n    total.className = 'roll-total';\n    total.textContent = 'Rolling...';\n    row.append(total);\n    stage.replaceChildren(row);\n    setTimeout(() => {\n        total.textContent = String(roll.total);\n        for (const die of Array.from(row.querySelectorAll('.die'))) {\n            die.classList.remove('rolling');\n        }\n    }, timing.rollDurationMs);\n    return window.setTimeout(() => {\n        overlay.classList.remove('visible');\n    }, timing.visibleDurationMs);\n};\n"
export const CLIENT_DOOR_LOS_VIEW_JS = "import { filterVisibleMapTargets } from '../../shared/mapAssets.js';\nexport const deriveDoorToggleViewModels = (board) => Object.values(board?.doors ?? {}).map((door) => ({\n    id: door.id,\n    open: door.open,\n    label: door.id,\n    stateLabel: door.open ? 'Open' : 'Closed',\n    toggleLabel: door.open ? `Close ${door.id}` : `Open ${door.id}`,\n    nextOpen: !door.open\n}));\nexport const derivePieceRectTargets = (pieces) => pieces.map((piece) => ({\n    id: piece.id,\n    rect: {\n        x: piece.x,\n        y: piece.y,\n        width: piece.width * piece.scale,\n        height: piece.height * piece.scale\n    }\n}));\nexport const deriveVisiblePieceIds = (sourcePieceId, pieces, occluders, doorStates = {}) => {\n    const targets = derivePieceRectTargets(pieces);\n    const source = targets.find((target) => target.id === sourcePieceId);\n    if (!source)\n        return [];\n    return filterVisibleMapTargets(source.rect, targets.filter((target) => target.id !== sourcePieceId), occluders, doorStates).map((target) => target.id);\n};\nexport const deriveLosOverlaySegments = (occluders, doorStates = {}) => occluders.map((occluder) => {\n    const currentDoorState = doorStates[occluder.id];\n    const open = occluder.type === 'door'\n        ? typeof currentDoorState === 'boolean'\n            ? currentDoorState\n            : (currentDoorState?.open ?? occluder.open)\n        : false;\n    const blocked = occluder.type === 'wall' || !open;\n    return {\n        id: occluder.id,\n        type: occluder.type,\n        x1: occluder.x1,\n        y1: occluder.y1,\n        x2: occluder.x2,\n        y2: occluder.y2,\n        open,\n        blocked,\n        label: occluder.type === 'wall'\n            ? `Wall ${occluder.id}`\n            : `${open ? 'Open' : 'Closed'} door ${occluder.id}`\n    };\n});\n"
export const CLIENT_IMAGE_ASSETS_JS = "export const cropStartsInsideImage = (crop, dimensions) => crop.x < dimensions.width && crop.y < dimensions.height;\nexport const readSelectedImageFileAsDataUrl = (input) => new Promise((resolve, reject) => {\n    const file = input.files?.[0];\n    if (!file) {\n        resolve(null);\n        return;\n    }\n    if (!file.type.startsWith('image/')) {\n        reject(new Error('Selected file must be an image'));\n        return;\n    }\n    const reader = new FileReader();\n    reader.addEventListener('load', () => {\n        resolve(typeof reader.result === 'string' ? reader.result : null);\n    });\n    reader.addEventListener('error', () => {\n        reject(new Error('Could not read selected image'));\n    });\n    reader.readAsDataURL(file);\n});\nexport const readSelectedCroppedImageFileAsDataUrl = (input, crop) => new Promise((resolve, reject) => {\n    const file = input.files?.[0];\n    if (!file) {\n        resolve(null);\n        return;\n    }\n    if (!file.type.startsWith('image/')) {\n        reject(new Error('Selected file must be an image'));\n        return;\n    }\n    const image = new Image();\n    const objectUrl = URL.createObjectURL(file);\n    const cleanup = () => URL.revokeObjectURL(objectUrl);\n    image.addEventListener('load', () => {\n        cleanup();\n        if (!cropStartsInsideImage(crop, {\n            width: image.naturalWidth,\n            height: image.naturalHeight\n        })) {\n            reject(new Error('Crop starts outside selected image'));\n            return;\n        }\n        const canvas = document.createElement('canvas');\n        canvas.width = crop.width;\n        canvas.height = crop.height;\n        const canvasContext = canvas.getContext('2d');\n        if (!canvasContext) {\n            reject(new Error('Could not crop selected image'));\n            return;\n        }\n        canvasContext.drawImage(image, crop.x, crop.y, crop.width, crop.height, 0, 0, crop.width, crop.height);\n        resolve(canvas.toDataURL('image/png'));\n    });\n    image.addEventListener('error', () => {\n        cleanup();\n        reject(new Error('Could not crop selected image'));\n    });\n    image.src = objectUrl;\n});\nexport const readImageDimensions = (file) => new Promise((resolve, reject) => {\n    if (!file.type.startsWith('image/')) {\n        reject(new Error('Selected file must be an image'));\n        return;\n    }\n    const image = new Image();\n    const objectUrl = URL.createObjectURL(file);\n    image.addEventListener('load', () => {\n        const dimensions = {\n            width: image.naturalWidth,\n            height: image.naturalHeight\n        };\n        URL.revokeObjectURL(objectUrl);\n        resolve(dimensions);\n    });\n    image.addEventListener('error', () => {\n        URL.revokeObjectURL(objectUrl);\n        reject(new Error('Could not inspect selected image'));\n    });\n    image.src = objectUrl;\n});\nexport const browserImageUrl = (value) => {\n    const imageRef = value || '';\n    if (imageRef.startsWith('/') ||\n        imageRef.startsWith('http://') ||\n        imageRef.startsWith('https://') ||\n        imageRef.startsWith('blob:') ||\n        imageRef.startsWith('data:image/')) {\n        return imageRef;\n    }\n    return null;\n};\nexport const cssUrl = (url) => `url(${JSON.stringify(url)})`;\nexport const loadBrowserImage = (url, cache, onLoad) => {\n    if (!url)\n        return null;\n    const cached = cache.get(url);\n    if (cached) {\n        return cached.loaded && !cached.failed ? cached.image : null;\n    }\n    const image = new Image();\n    image.decoding = 'async';\n    image.onload = () => {\n        const cachedState = cache.get(url);\n        if (cachedState)\n            cachedState.loaded = true;\n        onLoad();\n    };\n    image.onerror = () => {\n        const cachedState = cache.get(url);\n        if (cachedState)\n            cachedState.failed = true;\n    };\n    cache.set(url, { image, loaded: false, failed: false });\n    image.src = url;\n    return null;\n};\n"
export const CLIENT_MAP_ASSET_LIBRARY_JS = "import { validateLocalMapAssetMetadata } from '../../shared/mapAssets.js';\nconst LABEL_SEPARATOR_PATTERN = /[\\s_-]+/g;\nconst UNSAFE_LABEL_CHAR_PATTERN = /[<>&\"']/g;\nconst replaceControlCharacters = (value) => [...value]\n    .map((char) => {\n    const code = char.charCodeAt(0);\n    return code <= 31 || code === 127 ? ' ' : char;\n})\n    .join('');\nexport const validateMapAssetCandidates = (candidates) => {\n    const assets = [];\n    const errors = [];\n    for (const [index, candidate] of candidates.entries()) {\n        const result = validateLocalMapAssetMetadata(candidate);\n        if (result.ok) {\n            assets.push(result.value);\n            continue;\n        }\n        for (const error of result.error) {\n            errors.push(`Asset ${index}: ${error}`);\n        }\n    }\n    return { assets, errors };\n};\nexport const filterMapAssetCandidates = (assets, filters = {}) => assets.filter((asset) => {\n    if (filters.kind && asset.kind !== filters.kind)\n        return false;\n    if (filters.root && asset.root !== filters.root)\n        return false;\n    if (filters.tileKind && asset.tileKind !== filters.tileKind)\n        return false;\n    return true;\n});\nexport const groupMapAssetsByKind = (assets) => {\n    const groups = {\n        geomorph: [],\n        counter: []\n    };\n    for (const asset of assets) {\n        groups[asset.kind].push(asset);\n    }\n    return groups;\n};\nexport const groupMapAssetsByRoot = (assets) => {\n    const groups = {\n        Geomorphs: [],\n        Counters: []\n    };\n    for (const asset of assets) {\n        groups[asset.root].push(asset);\n    }\n    return groups;\n};\nexport const groupGeomorphAssetsByTileKind = (assets) => {\n    const groups = {\n        standard: [],\n        edge: [],\n        corner: [],\n        custom: []\n    };\n    for (const asset of assets) {\n        if (asset.tileKind) {\n            groups[asset.tileKind].push(asset);\n        }\n    }\n    return groups;\n};\nexport const deriveMapAssetLabel = (asset) => {\n    const pathParts = asset.relativePath.split(/[\\\\/]/).filter(Boolean);\n    const fileName = pathParts.at(-1) || asset.kind;\n    const extensionStart = fileName.lastIndexOf('.');\n    const baseName = extensionStart > 0 ? fileName.slice(0, extensionStart) : fileName;\n    const label = replaceControlCharacters(baseName)\n        .replace(UNSAFE_LABEL_CHAR_PATTERN, ' ')\n        .replace(LABEL_SEPARATOR_PATTERN, ' ')\n        .trim();\n    if (label.length > 0)\n        return label;\n    return asset.kind === 'geomorph' ? 'Geomorph asset' : 'Counter asset';\n};\nexport const deriveBoardDefaultsFromGeomorph = (asset) => {\n    if (asset.kind !== 'geomorph')\n        return null;\n    return {\n        width: asset.width,\n        height: asset.height,\n        scale: asset.gridScale\n    };\n};\nexport const chooseDefaultBoardDefaults = (assets, preferredTileKind = 'standard') => {\n    const geomorphs = filterMapAssetCandidates(assets, { kind: 'geomorph' });\n    const asset = geomorphs.find((candidate) => candidate.tileKind === preferredTileKind) ||\n        geomorphs[0];\n    return asset ? deriveBoardDefaultsFromGeomorph(asset) : null;\n};\n"
export const CLIENT_MAP_ASSET_PICKER_VIEW_JS = "import { deriveMapAssetLabel, validateMapAssetCandidates } from './map-asset-library.js';\nconst GEOMORPH_SECTION_ORDER = [\n    'standard',\n    'edge',\n    'corner',\n    'custom'\n];\nconst SECTION_TITLES = {\n    'geomorph-standard': 'Standard geomorph boards',\n    'geomorph-edge': 'Edge geomorph boards',\n    'geomorph-corner': 'Corner geomorph boards',\n    'geomorph-custom': 'Custom geomorph boards',\n    counter: 'Counters'\n};\nconst DEFAULT_VALIDATION_MESSAGE_LIMIT = 3;\nexport const buildLocalMapAssetRef = (asset) => `${asset.root}/${asset.relativePath}`;\nexport const deriveMapAssetDimensionsViewModel = (asset) => ({\n    width: asset.width,\n    height: asset.height,\n    gridScale: asset.gridScale,\n    label: `${asset.width} x ${asset.height} px, ${asset.gridScale} px grid`\n});\nexport const deriveGeomorphBoardCommandDefaults = (asset) => {\n    if (asset.kind !== 'geomorph')\n        return null;\n    return {\n        name: deriveMapAssetLabel(asset),\n        imageAssetId: buildLocalMapAssetRef(asset),\n        width: asset.width,\n        height: asset.height,\n        scale: asset.gridScale\n    };\n};\nexport const deriveCounterPieceCommandDefaults = (asset) => {\n    if (asset.kind !== 'counter')\n        return null;\n    return {\n        name: deriveMapAssetLabel(asset),\n        imageAssetId: buildLocalMapAssetRef(asset),\n        width: asset.width,\n        height: asset.height,\n        scale: asset.gridScale / Math.max(asset.width, asset.height)\n    };\n};\nexport const deriveMapAssetPickerItemViewModel = (asset) => ({\n    asset,\n    assetRef: buildLocalMapAssetRef(asset),\n    root: asset.root,\n    relativePath: asset.relativePath,\n    kind: asset.kind,\n    label: deriveMapAssetLabel(asset),\n    dimensions: deriveMapAssetDimensionsViewModel(asset),\n    tileKind: asset.tileKind,\n    boardDefaults: deriveGeomorphBoardCommandDefaults(asset),\n    pieceDefaults: deriveCounterPieceCommandDefaults(asset)\n});\nconst buildSection = (id, kind, tileKind, items) => {\n    if (items.length === 0)\n        return null;\n    return {\n        id,\n        title: SECTION_TITLES[id],\n        kind,\n        tileKind,\n        items\n    };\n};\nexport const deriveMapAssetPickerSections = (assets) => {\n    const items = assets.map(deriveMapAssetPickerItemViewModel);\n    const sections = [];\n    for (const tileKind of GEOMORPH_SECTION_ORDER) {\n        const section = buildSection(`geomorph-${tileKind}`, 'geomorph', tileKind, items.filter((item) => item.tileKind === tileKind));\n        if (section)\n            sections.push(section);\n    }\n    const counterSection = buildSection('counter', 'counter', null, items.filter((item) => item.kind === 'counter'));\n    if (counterSection)\n        sections.push(counterSection);\n    return sections;\n};\nexport const deriveMapAssetPickerEmptyState = (sections) => {\n    if (sections.some((section) => section.items.length > 0))\n        return null;\n    return {\n        title: 'No local map assets',\n        message: 'Validated Geomorphs or Counters metadata will appear here.'\n    };\n};\nexport const deriveMapAssetValidationSummary = (errors, messageLimit = DEFAULT_VALIDATION_MESSAGE_LIMIT) => {\n    const visibleErrors = errors.slice(0, Math.max(0, messageLimit));\n    const hiddenCount = errors.length - visibleErrors.length;\n    const messages = hiddenCount > 0\n        ? [...visibleErrors, `${hiddenCount} more validation error(s).`]\n        : visibleErrors;\n    return {\n        hasErrors: errors.length > 0,\n        errorCount: errors.length,\n        title: errors.length === 0\n            ? null\n            : `${errors.length} local map asset validation error(s)`,\n        messages\n    };\n};\nexport const deriveMapAssetPickerViewModel = (candidates) => {\n    const { assets, errors } = validateMapAssetCandidates(candidates);\n    const sections = deriveMapAssetPickerSections(assets);\n    return {\n        sections,\n        emptyState: deriveMapAssetPickerEmptyState(sections),\n        validationSummary: deriveMapAssetValidationSummary(errors)\n    };\n};\n"
export const CLIENT_PIECE_COMMAND_PLAN_JS = "import { uniqueCharacterId, uniquePieceId } from './bootstrap-flow.js';\nimport { createCharacterCreationFlow, deriveCharacterCreationCommands } from './character-creation-flow.js';\nconst sequenceCommandAt = (command, state, offset) => {\n    if (command.expectedSeq !== undefined || command.type === 'CreateGame') {\n        return command;\n    }\n    return {\n        ...command,\n        expectedSeq: state.eventSeq + offset\n    };\n};\nexport const createDefaultPieceCharacterCreationFlow = (characterId, name) => ({\n    ...createCharacterCreationFlow(characterId, {\n        name,\n        age: 30,\n        characteristics: {\n            str: 7,\n            dex: 7,\n            end: 7,\n            int: 7,\n            edu: 7,\n            soc: 7\n        },\n        skills: ['Athletics-0', 'Gun Combat-0'],\n        equipment: [],\n        credits: 0\n    }),\n    step: 'review'\n});\nexport const planCreatePieceCommands = ({ identity, state, board, name, imageAssetId, width, height, scale, existingPieceCount, withCharacterSheet }) => {\n    if (!state || !board) {\n        return {\n            ok: false,\n            error: 'Bootstrap a board before creating a piece',\n            focus: null\n        };\n    }\n    const trimmedName = name.trim();\n    if (!trimmedName) {\n        return {\n            ok: false,\n            error: 'Piece name is required',\n            focus: 'name'\n        };\n    }\n    const pieceId = uniquePieceId(state, trimmedName);\n    const characterId = withCharacterSheet\n        ? uniqueCharacterId(state, trimmedName)\n        : null;\n    const x = Math.max(0, Math.min(board.width - width * scale, 160 + (existingPieceCount % 8) * 58));\n    const y = Math.max(0, Math.min(board.height - height * scale, 140 + Math.floor(existingPieceCount / 8) * 58));\n    const characterCommands = characterId\n        ? deriveCharacterCreationCommands(createDefaultPieceCharacterCreationFlow(characterId, trimmedName), { identity, state })\n        : [];\n    if (characterId && characterCommands.length === 0) {\n        return {\n            ok: false,\n            error: 'Character creation needs the current room state',\n            focus: null\n        };\n    }\n    const createPieceCommand = sequenceCommandAt({\n        type: 'CreatePiece',\n        gameId: identity.gameId,\n        actorId: identity.actorId,\n        pieceId,\n        boardId: board.id,\n        name: trimmedName,\n        characterId,\n        imageAssetId,\n        x,\n        y,\n        width,\n        height,\n        scale\n    }, state, characterCommands.length);\n    return {\n        ok: true,\n        commands: [...characterCommands, createPieceCommand],\n        pieceId,\n        characterId\n    };\n};\n"
export const CLIENT_PWA_INSTALL_JS = "export const INSTALL_DISMISSED_KEY = 'cepheus-online-pwa-install-dismissed';\nexport const INSTALL_ACCEPTED_KEY = 'cepheus-online-pwa-install-accepted';\nconst isStandaloneDisplay = (windowTarget, navigatorLike) => windowTarget.matchMedia('(display-mode: standalone)').matches ||\n    navigatorLike.standalone === true;\nexport const createPwaInstallController = ({ elements, windowTarget = window, localStorage: storage = globalThis.localStorage, navigatorLike = navigator }) => {\n    let deferredInstallPrompt = null;\n    const hide = () => {\n        if (elements.prompt)\n            elements.prompt.hidden = true;\n    };\n    const refresh = () => {\n        if (!elements.prompt ||\n            !elements.installButton ||\n            !deferredInstallPrompt ||\n            isStandaloneDisplay(windowTarget, navigatorLike) ||\n            storage.getItem(INSTALL_DISMISSED_KEY) === '1' ||\n            storage.getItem(INSTALL_ACCEPTED_KEY) === '1') {\n            hide();\n            return;\n        }\n        elements.prompt.hidden = false;\n    };\n    windowTarget.addEventListener('beforeinstallprompt', (event) => {\n        event.preventDefault();\n        deferredInstallPrompt = event;\n        refresh();\n    });\n    windowTarget.addEventListener('appinstalled', () => {\n        storage.setItem(INSTALL_ACCEPTED_KEY, '1');\n        deferredInstallPrompt = null;\n        hide();\n    });\n    elements.installButton?.addEventListener('click', async () => {\n        if (!deferredInstallPrompt)\n            return;\n        const promptEvent = deferredInstallPrompt;\n        deferredInstallPrompt = null;\n        hide();\n        await promptEvent.prompt();\n        const choice = await promptEvent.userChoice;\n        if (choice.outcome === 'accepted') {\n            storage.setItem(INSTALL_ACCEPTED_KEY, '1');\n        }\n    });\n    elements.dismissButton?.addEventListener('click', () => {\n        storage.setItem(INSTALL_DISMISSED_KEY, '1');\n        hide();\n    });\n    return { refresh, hide };\n};\n"
export const CLIENT_ROOM_API_JS = "const resolveFetch = (fetcher) => fetcher ?? fetch;\nexport const buildRoomPath = (roomId) => `/rooms/${encodeURIComponent(roomId)}`;\nexport const buildViewerQuery = (viewerRole, actorId) => '?viewer=' +\n    encodeURIComponent(viewerRole) +\n    '&user=' +\n    encodeURIComponent(actorId);\nexport const buildCommandMessage = (requestId, command) => ({\n    type: 'command',\n    requestId,\n    command\n});\nexport const fetchRoomState = async ({ roomId, viewerRole, actorId, fetch: fetcher }) => {\n    const response = await resolveFetch(fetcher)(`${buildRoomPath(roomId)}/state${buildViewerQuery(viewerRole, actorId)}`);\n    return response.json();\n};\nexport const postRoomCommand = async ({ roomId, requestId, command, fetch: fetcher }) => {\n    const response = await resolveFetch(fetcher)(`${buildRoomPath(roomId)}/command`, {\n        method: 'POST',\n        headers: { 'content-type': 'application/json' },\n        body: JSON.stringify(buildCommandMessage(requestId, command))\n    });\n    const message = (await response.json());\n    return {\n        ok: response.ok,\n        message\n    };\n};\n"
export const CLIENT_ROOM_MENU_CONTROLLER_JS = "export const resolveRoomIdentity = (roomValue, userValue, defaultRoomId, defaultActorId) => ({\n    roomId: roomValue.trim() || defaultRoomId,\n    actorId: userValue.trim() || defaultActorId\n});\nconst updateRoomUrl = (identity, locationLike, historyLike) => {\n    const nextUrl = new URL(locationLike.href);\n    nextUrl.searchParams.set('game', identity.roomId);\n    nextUrl.searchParams.set('user', identity.actorId);\n    historyLike.replaceState(null, '', nextUrl);\n};\nexport const createRoomMenuController = ({ elements, initialRoomId, initialActorId, defaultRoomId, defaultActorId, locationLike, historyLike, onOpenRoom }) => {\n    elements.roomInput.value = initialRoomId;\n    elements.userInput.value = initialActorId;\n    elements.roomForm.addEventListener('submit', (event) => {\n        event.preventDefault();\n        const identity = resolveRoomIdentity(elements.roomInput.value, elements.userInput.value, defaultRoomId, defaultActorId);\n        updateRoomUrl(identity, locationLike ?? globalThis.location, historyLike ?? globalThis.history);\n        elements.roomDialog.close();\n        onOpenRoom(identity);\n    });\n    elements.menuButton.addEventListener('click', () => {\n        elements.roomDialog.showModal();\n    });\n    elements.roomCancelButton.addEventListener('click', () => {\n        elements.roomDialog.close();\n    });\n};\n"
export const CLIENT_SERVICE_WORKER_JS = "export const registerClientServiceWorker = ({ navigatorLike = navigator, locationLike = location, scriptUrl = '/sw.js' } = {}) => {\n    if (!('serviceWorker' in navigatorLike))\n        return;\n    const serviceWorker = navigatorLike.serviceWorker;\n    let hadServiceWorkerController = serviceWorker.controller !== null;\n    let isReloadingForServiceWorker = false;\n    serviceWorker.register(scriptUrl).catch(() => { });\n    serviceWorker.addEventListener('controllerchange', () => {\n        if (!hadServiceWorkerController) {\n            hadServiceWorkerController = true;\n            return;\n        }\n        if (isReloadingForServiceWorker)\n            return;\n        isReloadingForServiceWorker = true;\n        locationLike.reload();\n    });\n};\n"
export const CLIENT_GAME_COMMANDS_JS = "import { asBoardId, asCharacterId, asGameId, asPieceId, asUserId } from '../shared/ids';\nexport const DEFAULT_GAME_ID = 'demo-room';\nexport const DEFAULT_ACTOR_ID = 'local-user';\nexport const DEFAULT_BOARD_ID = asBoardId('main-board');\nexport const DEFAULT_CHARACTER_ID = asCharacterId('scout');\nexport const DEFAULT_PIECE_ID = asPieceId('scout-1');\nconst CHARACTERISTIC_KEYS = [\n    'str',\n    'dex',\n    'end',\n    'int',\n    'edu',\n    'soc'\n];\nexport const resolveClientIdentity = (searchParams) => ({\n    gameId: asGameId(searchParams.get('game') ?? DEFAULT_GAME_ID),\n    actorId: asUserId(searchParams.get('user') ?? DEFAULT_ACTOR_ID)\n});\nexport const buildCommandMessage = (requestId, command) => ({\n    type: 'command',\n    requestId,\n    command\n});\nexport const buildSequencedCommand = (command, state) => {\n    if (!state || command.expectedSeq !== undefined)\n        return command;\n    if (command.type === 'CreateGame')\n        return command;\n    return {\n        ...command,\n        expectedSeq: state.eventSeq\n    };\n};\nexport const buildCreateGameCommand = ({ identity }) => ({\n    type: 'CreateGame',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    slug: identity.gameId,\n    name: `Cepheus Room ${identity.gameId}`\n});\nexport const buildCreateBoardCommand = ({ identity }) => ({\n    type: 'CreateBoard',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    boardId: DEFAULT_BOARD_ID,\n    name: 'Downport Skirmish',\n    width: 1200,\n    height: 800,\n    scale: 50\n});\nexport const buildCreateCharacterCommand = ({ identity, characterId = DEFAULT_CHARACTER_ID }) => ({\n    type: 'CreateCharacter',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    characterId,\n    characterType: 'PLAYER',\n    name: 'Scout'\n});\nexport const normalizeCharacterSkillList = (value) => {\n    const rawSkills = typeof value === 'string' ? value.split(/[\\n,]/) : Array.from(value);\n    const skills = [];\n    const seen = new Set();\n    for (const rawSkill of rawSkills) {\n        const skill = rawSkill.trim();\n        const key = skill.toLowerCase();\n        if (!skill || seen.has(key))\n            continue;\n        skills.push(skill);\n        seen.add(key);\n    }\n    return skills;\n};\nexport const normalizeCharacterEquipmentText = (value) => {\n    const equipment = [];\n    for (const line of value.split('\\n')) {\n        const [rawName = '', rawQuantity = '1', ...rawNotes] = line\n            .split('|')\n            .map((part) => part.trim());\n        const name = rawName.trim();\n        if (!name)\n            continue;\n        const quantity = Number.parseInt(rawQuantity, 10);\n        equipment.push({\n            name,\n            quantity: Number.isFinite(quantity) && quantity > 0 ? quantity : 1,\n            notes: rawNotes.join(' | ').trim()\n        });\n    }\n    return equipment;\n};\nexport const formatCharacterEquipmentText = (equipment) => equipment\n    .map((item) => [item.name, item.quantity, item.notes].join(' | '))\n    .join('\\n');\nconst formValue = (value) => {\n    if (value === undefined)\n        return null;\n    if (value && typeof value === 'object' && 'value' in value) {\n        return formValue(value.value);\n    }\n    return value;\n};\nconst parseNullableFormNumber = (value) => {\n    const rawValue = formValue(value);\n    if (rawValue === null)\n        return null;\n    if (typeof rawValue === 'number') {\n        return Number.isFinite(rawValue) ? rawValue : null;\n    }\n    const trimmed = rawValue.trim();\n    if (!trimmed)\n        return null;\n    const number = Number.parseInt(trimmed, 10);\n    return Number.isFinite(number) ? number : null;\n};\nexport const parseCharacterCharacteristicsPatch = (values) => {\n    const characteristics = {};\n    for (const key of CHARACTERISTIC_KEYS) {\n        const upperKey = key.toUpperCase();\n        if (values[key] === undefined && values[upperKey] === undefined)\n            continue;\n        characteristics[key] = parseNullableFormNumber(values[key] ?? values[upperKey]);\n    }\n    return characteristics;\n};\nexport const buildCharacterSkillRollReason = ({ character, skill, fallbackName = 'Character' }) => {\n    const characterName = character?.name.trim() || fallbackName;\n    const skillName = skill.trim() || 'Skill';\n    return `${characterName}: ${skillName}`;\n};\nconst hasCharacterSheetPatch = (patch) => patch.notes !== undefined ||\n    patch.age !== undefined ||\n    patch.characteristics !== undefined ||\n    patch.skills !== undefined ||\n    patch.equipment !== undefined ||\n    patch.credits !== undefined;\nconst normalizeCharacterSheetPatch = (patch) => {\n    const normalized = {};\n    if (patch.notes !== undefined)\n        normalized.notes = patch.notes;\n    if (patch.age !== undefined)\n        normalized.age = patch.age;\n    if (patch.characteristics !== undefined) {\n        normalized.characteristics = { ...patch.characteristics };\n    }\n    if (patch.skillsText !== undefined) {\n        normalized.skills = normalizeCharacterSkillList(patch.skillsText);\n    }\n    else if (patch.skills !== undefined) {\n        normalized.skills = normalizeCharacterSkillList(patch.skills);\n    }\n    if (patch.equipmentText !== undefined) {\n        normalized.equipment = normalizeCharacterEquipmentText(patch.equipmentText);\n    }\n    else if (patch.equipment !== undefined) {\n        normalized.equipment = patch.equipment.map((item) => ({ ...item }));\n    }\n    if (patch.credits !== undefined)\n        normalized.credits = patch.credits;\n    return normalized;\n};\nexport const buildCharacterSheetPatchCommand = ({ identity, character, patch }) => {\n    if (!character)\n        return null;\n    const normalizedPatch = normalizeCharacterSheetPatch(patch);\n    if (!hasCharacterSheetPatch(normalizedPatch))\n        return null;\n    return {\n        type: 'UpdateCharacterSheet',\n        gameId: identity.gameId,\n        actorId: identity.actorId,\n        characterId: character.id,\n        ...normalizedPatch\n    };\n};\nexport const buildDefaultCharacterSheetUpdateCommand = ({ identity, characterId = DEFAULT_CHARACTER_ID }) => ({\n    type: 'UpdateCharacterSheet',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    characterId,\n    age: 34,\n    characteristics: {\n        str: 7,\n        dex: 8,\n        end: 8,\n        int: 7,\n        edu: 9,\n        soc: 6\n    },\n    skills: ['Vacc Suit-0', 'Gun Combat-0', 'Mechanic-0', 'Recon-0'],\n    equipment: [\n        { name: 'Vacc Suit', quantity: 1, notes: 'Carried' },\n        {\n            name: 'Laser Carbine',\n            quantity: 1,\n            notes: 'Carried'\n        },\n        {\n            name: 'Medkit',\n            quantity: 1,\n            notes: 'Stowed'\n        }\n    ],\n    credits: 1200\n});\nexport const buildStartCharacterCreationCommand = ({ identity, characterId = DEFAULT_CHARACTER_ID }) => ({\n    type: 'StartCharacterCreation',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    characterId\n});\nexport const buildSetCharacterCharacteristicsCreationCommand = ({ identity, characterId = DEFAULT_CHARACTER_ID }) => ({\n    type: 'AdvanceCharacterCreation',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    characterId,\n    creationEvent: { type: 'SET_CHARACTERISTICS' }\n});\nexport const buildCompleteCharacterHomeworldCreationCommand = ({ identity, characterId = DEFAULT_CHARACTER_ID }) => ({\n    type: 'AdvanceCharacterCreation',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    characterId,\n    creationEvent: { type: 'COMPLETE_HOMEWORLD' }\n});\nexport const buildStartCharacterCareerTermCommand = ({ identity, characterId = DEFAULT_CHARACTER_ID, career = 'Scout' }) => ({\n    type: 'StartCharacterCareerTerm',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    characterId,\n    career\n});\nexport const buildSelectCharacterCareerCreationCommand = ({ identity, characterId = DEFAULT_CHARACTER_ID }) => ({\n    type: 'AdvanceCharacterCreation',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    characterId,\n    creationEvent: {\n        type: 'SELECT_CAREER',\n        isNewCareer: true\n    }\n});\nexport const buildCreatePieceCommand = ({ identity, boardId = DEFAULT_BOARD_ID, characterId = null, imageAssetId = null, width = 50, height = 50, scale = 1 }) => ({\n    type: 'CreatePiece',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    pieceId: DEFAULT_PIECE_ID,\n    boardId,\n    characterId,\n    name: 'Scout',\n    imageAssetId,\n    x: 220,\n    y: 180,\n    width,\n    height,\n    scale\n});\nexport const buildMovePieceCommand = ({ identity, state, pieceId, x, y }) => ({\n    type: 'MovePiece',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    pieceId,\n    x,\n    y,\n    expectedSeq: state.eventSeq\n});\nexport const buildSetDoorOpenCommand = ({ identity, state, boardId, doorId, open }) => ({\n    type: 'SetDoorOpen',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    boardId,\n    doorId,\n    open,\n    expectedSeq: state.eventSeq\n});\nexport const buildRollDiceCommand = ({ identity, expression, reason }) => ({\n    type: 'RollDice',\n    gameId: identity.gameId,\n    actorId: identity.actorId,\n    expression,\n    reason\n});\nexport const buildBootstrapCommands = (identity, state) => {\n    if (!state) {\n        return [buildCreateGameCommand({ requestId: 'bootstrap-game', identity })];\n    }\n    if (Object.keys(state.boards).length === 0) {\n        return [\n            buildSequencedCommand(buildCreateBoardCommand({ requestId: 'bootstrap-board', identity }), state)\n        ];\n    }\n    const scout = state.characters[DEFAULT_CHARACTER_ID];\n    if (!scout) {\n        return [\n            buildSequencedCommand(buildCreateCharacterCommand({\n                requestId: 'bootstrap-character',\n                identity\n            }), state)\n        ];\n    }\n    if (!scout.creation) {\n        return [\n            buildSequencedCommand(buildStartCharacterCreationCommand({\n                requestId: 'bootstrap-character-creation',\n                identity\n            }), state)\n        ];\n    }\n    if (scout.creation.state.status === 'CHARACTERISTICS') {\n        return [\n            buildSequencedCommand(buildSetCharacterCharacteristicsCreationCommand({\n                requestId: 'bootstrap-characteristics',\n                identity\n            }), state)\n        ];\n    }\n    if (scout.creation.state.status === 'HOMEWORLD') {\n        return [\n            buildSequencedCommand(buildCompleteCharacterHomeworldCreationCommand({\n                requestId: 'bootstrap-homeworld',\n                identity\n            }), state)\n        ];\n    }\n    if (scout.creation.terms.length === 0) {\n        return [\n            buildSequencedCommand(buildStartCharacterCareerTermCommand({\n                requestId: 'bootstrap-career-term',\n                identity\n            }), state)\n        ];\n    }\n    if (scout.creation.state.status === 'CAREER_SELECTION') {\n        return [\n            buildSequencedCommand(buildSelectCharacterCareerCreationCommand({\n                requestId: 'bootstrap-career-selection',\n                identity\n            }), state)\n        ];\n    }\n    if ((scout.skills || []).length === 0) {\n        return [\n            buildSequencedCommand(buildDefaultCharacterSheetUpdateCommand({\n                requestId: 'bootstrap-character-sheet',\n                identity\n            }), state)\n        ];\n    }\n    if (Object.keys(state.pieces).length === 0) {\n        const boardId = (state.selectedBoardId ??\n            Object.keys(state.boards)[0]);\n        const characterId = (state.characters[DEFAULT_CHARACTER_ID]\n            ? DEFAULT_CHARACTER_ID\n            : Object.keys(state.characters)[0]);\n        return [\n            buildSequencedCommand(buildCreatePieceCommand({\n                requestId: 'bootstrap-piece',\n                identity,\n                boardId,\n                characterId\n            }), state)\n        ];\n    }\n    return [];\n};\nexport const applyServerMessage = (currentState, message) => {\n    switch (message.type) {\n        case 'roomState':\n            return {\n                state: message.state,\n                shouldApplyState: true,\n                shouldReload: false,\n                error: null\n            };\n        case 'commandAccepted':\n            return {\n                state: message.state,\n                shouldApplyState: true,\n                shouldReload: false,\n                error: null\n            };\n        case 'commandRejected':\n            return {\n                state: currentState,\n                shouldApplyState: false,\n                shouldReload: message.error.code === 'stale_command',\n                error: message.error.message\n            };\n        case 'error':\n            return {\n                state: currentState,\n                shouldApplyState: false,\n                shouldReload: false,\n                error: message.error.message\n            };\n        case 'pong':\n            return {\n                state: currentState,\n                shouldApplyState: false,\n                shouldReload: false,\n                error: null\n            };\n        default: {\n            const exhaustive = message;\n            return {\n                state: currentState,\n                shouldApplyState: false,\n                shouldReload: false,\n                error: `Unhandled message ${exhaustive.type}`\n            };\n        }\n    }\n};\n"
export const CLIENT_DICE_JS = "export const DICE_ROLL_ANIMATION_MS = 2200;\nexport const DICE_OVERLAY_VISIBLE_MS = 6200;\nexport const DICE_REVEAL_MIN_MS = 500;\nexport const DICE_REVEALED_HOLD_MS = 3600;\nexport const DICE_PIP_SLOTS = {\n    1: ['center'],\n    2: ['top-left', 'bottom-right'],\n    3: ['top-left', 'center', 'bottom-right'],\n    4: ['top-left', 'top-right', 'bottom-left', 'bottom-right'],\n    5: ['top-left', 'top-right', 'center', 'bottom-left', 'bottom-right'],\n    6: [\n        'top-left',\n        'top-right',\n        'middle-left',\n        'middle-right',\n        'bottom-left',\n        'bottom-right'\n    ]\n};\nexport const deriveD6Face = (value) => ((((((Math.trunc(value) || 1) - 1) % 6) + 6) % 6) + 1);\nexport const deriveDicePipSlots = (value) => DICE_PIP_SLOTS[value] ?? null;\nexport const deriveDieFaces = (value) => {\n    const base = deriveD6Face(value);\n    return [\n        { name: 'front', value },\n        { name: 'back', value: 7 - base },\n        { name: 'right', value: deriveD6Face(base + 1) },\n        { name: 'left', value: deriveD6Face(base + 3) },\n        { name: 'top', value: deriveD6Face(base + 4) },\n        { name: 'bottom', value: deriveD6Face(base + 2) }\n    ];\n};\nexport const deriveDieTilt = (index) => index % 2 === 0\n    ? { x: '-22deg', y: '-34deg', z: '1deg' }\n    : { x: '-18deg', y: '-24deg', z: '-4deg' };\nexport const deriveDiceRollTiming = ({ revealAt, nowMs, maxRollDurationMs = DICE_ROLL_ANIMATION_MS, minRollDurationMs = DICE_REVEAL_MIN_MS, overlayVisibleMs = DICE_OVERLAY_VISIBLE_MS, revealedHoldMs = DICE_REVEALED_HOLD_MS }) => {\n    const revealAtMs = Date.parse(revealAt ?? '');\n    const timeUntilReveal = Number.isFinite(revealAtMs)\n        ? revealAtMs - nowMs\n        : maxRollDurationMs;\n    const rollDurationMs = Math.max(minRollDurationMs, Math.min(maxRollDurationMs, timeUntilReveal));\n    return {\n        rollDurationMs,\n        visibleDurationMs: Math.max(overlayVisibleMs, rollDurationMs + revealedHoldMs)\n    };\n};\n"
export const SHARED_MAP_ASSETS_JS = "import { err, ok } from './result';\nimport { isObject } from './util';\nexport const LOCAL_MAP_ASSET_ROOTS = ['Geomorphs', 'Counters'];\nconst isLocalMapAssetRoot = (value) => LOCAL_MAP_ASSET_ROOTS.includes(value);\nconst isMapAssetKind = (value) => value === 'geomorph' || value === 'counter';\nconst isPositiveFiniteNumber = (value) => typeof value === 'number' && Number.isFinite(value) && value > 0;\nconst isFiniteNumber = (value) => typeof value === 'number' && Number.isFinite(value);\nconst hasUnsafePathSegment = (path) => path\n    .split(/[\\\\/]/)\n    .some((segment) => segment === '' || segment === '.' || segment === '..');\nconst isCoordinateInBounds = (value, max) => isFiniteNumber(value) && value >= 0 && value <= max;\nconst pushSegmentErrors = (errors, occluder, index, width, height) => {\n    const { x1, y1, x2, y2 } = occluder;\n    if (!isCoordinateInBounds(x1, width)) {\n        errors.push(`Occluder ${index} x1 must be within map bounds.`);\n    }\n    if (!isCoordinateInBounds(x2, width)) {\n        errors.push(`Occluder ${index} x2 must be within map bounds.`);\n    }\n    if (!isCoordinateInBounds(y1, height)) {\n        errors.push(`Occluder ${index} y1 must be within map bounds.`);\n    }\n    if (!isCoordinateInBounds(y2, height)) {\n        errors.push(`Occluder ${index} y2 must be within map bounds.`);\n    }\n    if (x1 === x2 && y1 === y2) {\n        errors.push(`Occluder ${index} must have a non-zero segment length.`);\n    }\n};\nconst validateMapOccluder = (value, index, width, height, seenIds) => {\n    const errors = [];\n    if (!isObject(value)) {\n        return err([`Occluder ${index} must be an object.`]);\n    }\n    const { type, id, x1, y1, x2, y2, open } = value;\n    if (type !== 'wall' && type !== 'door') {\n        errors.push(`Occluder ${index} type must be wall or door.`);\n    }\n    if (typeof id !== 'string' || id.length === 0) {\n        errors.push(`Occluder ${index} id is required.`);\n    }\n    else if (seenIds.has(id)) {\n        errors.push(`Occluder ${index} id must be unique.`);\n    }\n    else {\n        seenIds.add(id);\n    }\n    pushSegmentErrors(errors, value, index, width, height);\n    if (type === 'door' && typeof open !== 'boolean') {\n        errors.push(`Occluder ${index} door open state must be boolean.`);\n    }\n    if (errors.length > 0)\n        return err(errors);\n    const segment = { id, x1, y1, x2, y2 };\n    if (type === 'door') {\n        return ok({\n            type,\n            ...segment,\n            open\n        });\n    }\n    return ok({\n        type,\n        ...segment\n    });\n};\nexport const deriveGeomorphTileKind = (width, height) => {\n    if (width === 1000 && height === 1000)\n        return 'standard';\n    if (width === 1000 && height === 530)\n        return 'edge';\n    if (width === 530 && height === 530)\n        return 'corner';\n    return 'custom';\n};\nexport const validateLocalMapAssetMetadata = (value) => {\n    const errors = [];\n    if (!isObject(value)) {\n        return err(['Metadata must be an object.']);\n    }\n    const { root, relativePath, kind, width, height, gridScale } = value;\n    if (!isLocalMapAssetRoot(root)) {\n        errors.push('Root must be Geomorphs or Counters.');\n    }\n    if (typeof relativePath !== 'string' || relativePath.length === 0) {\n        errors.push('Relative path is required.');\n    }\n    else if (relativePath.startsWith('/') ||\n        /^[A-Za-z]:[\\\\/]/.test(relativePath) ||\n        hasUnsafePathSegment(relativePath)) {\n        errors.push('Relative path must stay inside the local asset root.');\n    }\n    if (!isMapAssetKind(kind)) {\n        errors.push('Kind must be geomorph or counter.');\n    }\n    else if (root === 'Geomorphs' && kind !== 'geomorph') {\n        errors.push('Geomorphs assets must use geomorph kind.');\n    }\n    else if (root === 'Counters' && kind !== 'counter') {\n        errors.push('Counters assets must use counter kind.');\n    }\n    if (!isPositiveFiniteNumber(width))\n        errors.push('Width must be positive.');\n    if (!isPositiveFiniteNumber(height))\n        errors.push('Height must be positive.');\n    if (!isPositiveFiniteNumber(gridScale)) {\n        errors.push('Grid scale must be positive.');\n    }\n    if (errors.length > 0)\n        return err(errors);\n    const metadata = {\n        root,\n        relativePath,\n        kind,\n        width,\n        height,\n        gridScale\n    };\n    const tileKind = metadata.kind === 'geomorph'\n        ? deriveGeomorphTileKind(metadata.width, metadata.height)\n        : null;\n    return ok({\n        ...metadata,\n        tileKind\n    });\n};\nexport const validateMapLosSidecar = (value) => {\n    const errors = [];\n    if (!isObject(value)) {\n        return err(['LOS sidecar must be an object.']);\n    }\n    const { assetRef, width, height, gridScale, occluders } = value;\n    if (typeof assetRef !== 'string' || assetRef.length === 0) {\n        errors.push('Asset reference is required.');\n    }\n    if (!isPositiveFiniteNumber(width))\n        errors.push('Width must be positive.');\n    if (!isPositiveFiniteNumber(height))\n        errors.push('Height must be positive.');\n    if (!isPositiveFiniteNumber(gridScale)) {\n        errors.push('Grid scale must be positive.');\n    }\n    if (!Array.isArray(occluders)) {\n        errors.push('Occluders must be an array.');\n    }\n    if (errors.length > 0)\n        return err(errors);\n    const validWidth = width;\n    const validHeight = height;\n    const seenIds = new Set();\n    const validOccluders = [];\n    for (const [index, occluder] of occluders.entries()) {\n        const result = validateMapOccluder(occluder, index, validWidth, validHeight, seenIds);\n        if (result.ok) {\n            validOccluders.push(result.value);\n        }\n        else {\n            errors.push(...result.error);\n        }\n    }\n    if (errors.length > 0)\n        return err(errors);\n    return ok({\n        assetRef,\n        width: validWidth,\n        height: validHeight,\n        gridScale: gridScale,\n        occluders: validOccluders\n    });\n};\nconst orientation = (a, b, c) => {\n    const cross = (b.y - a.y) * (c.x - b.x) - (b.x - a.x) * (c.y - b.y);\n    if (cross === 0)\n        return 0;\n    return cross > 0 ? 1 : -1;\n};\nconst isPointOnSegment = (point, segmentStart, segmentEnd) => point.x >= Math.min(segmentStart.x, segmentEnd.x) &&\n    point.x <= Math.max(segmentStart.x, segmentEnd.x) &&\n    point.y >= Math.min(segmentStart.y, segmentEnd.y) &&\n    point.y <= Math.max(segmentStart.y, segmentEnd.y);\nexport const doMapSegmentsIntersect = (first, second) => {\n    const firstStart = { x: first.x1, y: first.y1 };\n    const firstEnd = { x: first.x2, y: first.y2 };\n    const secondStart = { x: second.x1, y: second.y1 };\n    const secondEnd = { x: second.x2, y: second.y2 };\n    const o1 = orientation(firstStart, firstEnd, secondStart);\n    const o2 = orientation(firstStart, firstEnd, secondEnd);\n    const o3 = orientation(secondStart, secondEnd, firstStart);\n    const o4 = orientation(secondStart, secondEnd, firstEnd);\n    if (o1 !== o2 && o3 !== o4)\n        return true;\n    return ((o1 === 0 && isPointOnSegment(secondStart, firstStart, firstEnd)) ||\n        (o2 === 0 && isPointOnSegment(secondEnd, firstStart, firstEnd)) ||\n        (o3 === 0 && isPointOnSegment(firstStart, secondStart, secondEnd)) ||\n        (o4 === 0 && isPointOnSegment(firstEnd, secondStart, secondEnd)));\n};\nexport const isMapDoorOpen = (door, doorStates = {}) => {\n    const boardState = doorStates[door.id];\n    if (typeof boardState === 'boolean')\n        return boardState;\n    if (boardState !== undefined)\n        return boardState.open;\n    return door.open;\n};\nexport const isBlockingMapOccluder = (occluder, doorStates = {}) => occluder.type === 'wall' || !isMapDoorOpen(occluder, doorStates);\nexport const filterBlockingMapOccluders = (occluders, doorStates = {}) => occluders.filter((occluder) => isBlockingMapOccluder(occluder, doorStates));\nexport const findBlockingMapOccluderForSegment = (segment, occluders, doorStates = {}) => occluders.find((occluder) => isBlockingMapOccluder(occluder, doorStates) &&\n    doMapSegmentsIntersect(segment, occluder)) ?? null;\nexport const hasMapLineOfSight = (from, to, occluders, doorStates = {}) => findBlockingMapOccluderForSegment({ x1: from.x, y1: from.y, x2: to.x, y2: to.y }, occluders, doorStates) === null;\nexport const mapRectCenter = (rect) => ({\n    x: rect.x + rect.width / 2,\n    y: rect.y + rect.height / 2\n});\nexport const hasMapRectCenterLineOfSight = (from, to, occluders, doorStates = {}) => hasMapLineOfSight(mapRectCenter(from), mapRectCenter(to), occluders, doorStates);\nexport const filterVisibleMapTargets = (from, targets, occluders, doorStates = {}) => targets.filter((target) => hasMapRectCenterLineOfSight(from, target.rect, occluders, doorStates));\n"
export const SHARED_CHARACTER_CREATION_CAREER_RULES_JS = "export const characteristicModifier = (characteristic) => (characteristic == null ? 0 : Math.floor(characteristic / 3) - 2);\nexport const parseCareerCheck = (check) => {\n    const trimmed = check.trim();\n    if (!trimmed || trimmed === '-')\n        return null;\n    const plainTarget = /^(\\d+)\\+$/.exec(trimmed);\n    if (plainTarget) {\n        return { characteristic: null, target: Number(plainTarget[1]) };\n    }\n    const characteristicTarget = /^(Str|Dex|End|Int|Edu|Soc)\\s+(\\d+)\\+$/i.exec(trimmed);\n    if (!characteristicTarget)\n        return null;\n    return {\n        characteristic: characteristicTarget[1].toLowerCase(),\n        target: Number(characteristicTarget[2])\n    };\n};\nexport const evaluateCareerCheck = ({ check, characteristics, roll, dm = 0 }) => {\n    const parsed = parseCareerCheck(check);\n    if (!parsed)\n        return null;\n    const modifier = dm +\n        (parsed.characteristic\n            ? characteristicModifier(characteristics[parsed.characteristic])\n            : 0);\n    const total = roll + modifier;\n    return {\n        check: parsed,\n        modifier,\n        total,\n        success: total >= parsed.target\n    };\n};\nexport const deriveCareerQualificationDm = (previousCareerCount) => (previousCareerCount > 0 ? previousCareerCount * -2 : 0);\nexport const availableCareerNames = (careerBasics, servedCareerNames = []) => {\n    const unavailable = new Set(servedCareerNames.filter((career) => career !== 'Drifter'));\n    return Object.keys(careerBasics).filter((career) => !unavailable.has(career));\n};\nexport const deriveBasicTrainingPlan = ({ career, serviceSkills, completedTermCount, previousCareerNames }) => {\n    const skills = Object.values(serviceSkills[career] ?? {});\n    if (skills.length === 0)\n        return { kind: 'none', skills: [] };\n    if (completedTermCount === 0) {\n        return { kind: 'all', skills };\n    }\n    const careerTerms = previousCareerNames.filter((name) => name === career);\n    return careerTerms.length === 0\n        ? { kind: 'choose-one', skills }\n        : { kind: 'none', skills: [] };\n};\nexport const deriveSurvivalPromotionOptions = (careerBasics, currentRank) => ({\n    canCommission: currentRank === 0 && careerBasics.Commission !== '-',\n    canAdvance: currentRank > 0 && careerBasics.Advancement !== '-'\n});\n"
