export const SHARED_CHARACTER_CREATION_SKILLS_JS = "export const isCascadeCareerSkill = (skill) => skill.includes('*');\nexport const formatCareerSkill = ({ name, level }) => `${name}-${level}`;\nexport const parseCareerSkill = (skill) => {\n    const trimmed = skill.trim();\n    if (!trimmed)\n        return null;\n    const parsed = /^(.*?)-(-?\\d+)$/.exec(trimmed);\n    if (!parsed)\n        return { name: trimmed, level: 0 };\n    const name = parsed[1].trim();\n    if (!name)\n        return null;\n    return {\n        name,\n        level: Number(parsed[2])\n    };\n};\nexport const careerSkillWithLevel = (skill, level) => skill.trim().replace('*', `-${level}`);\nexport const normalizeCareerSkill = (skill, defaultLevel = 1) => {\n    const trimmed = skill.trim();\n    if (!trimmed)\n        return null;\n    if (isCascadeCareerSkill(trimmed)) {\n        return careerSkillWithLevel(trimmed, defaultLevel);\n    }\n    const parsed = parseCareerSkill(trimmed);\n    if (!parsed)\n        return null;\n    return formatCareerSkill({\n        name: parsed.name,\n        level: /-(-?\\d+)$/.test(trimmed) ? parsed.level : defaultLevel\n    });\n};\nexport const tallyCareerSkills = (skills) => {\n    const totals = new Map();\n    for (const skill of skills) {\n        if (isCascadeCareerSkill(skill))\n            continue;\n        const parsed = parseCareerSkill(skill);\n        if (!parsed)\n            continue;\n        totals.set(parsed.name, (totals.get(parsed.name) ?? 0) + parsed.level);\n    }\n    return [...totals.entries()]\n        .sort(([leftName, leftLevel], [rightName, rightLevel]) => {\n        if (rightLevel !== leftLevel)\n            return rightLevel - leftLevel;\n        return leftName.localeCompare(rightName);\n    })\n        .map(([name, level]) => formatCareerSkill({ name, level }));\n};\nexport const resolveCascadeCareerSkill = ({ pendingCascadeSkills, backgroundSkills = [], careerSkills = [], termSkills = [], cascadeSkill, selection, basicTraining = false }) => {\n    const remaining = pendingCascadeSkills.filter((skill) => skill !== cascadeSkill);\n    const parsed = parseCareerSkill(cascadeSkill);\n    const level = parsed?.level ?? 0;\n    if (isCascadeCareerSkill(selection)) {\n        return {\n            pendingCascadeSkills: [...remaining, careerSkillWithLevel(selection, level)],\n            backgroundSkills: [...backgroundSkills],\n            careerSkills: [...careerSkills],\n            termSkills: [...termSkills]\n        };\n    }\n    const resolvedSkill = formatCareerSkill({\n        name: selection.trim(),\n        level\n    });\n    return {\n        pendingCascadeSkills: remaining,\n        backgroundSkills: basicTraining\n            ? [...backgroundSkills, resolvedSkill]\n            : [...backgroundSkills],\n        careerSkills: basicTraining\n            ? [...careerSkills]\n            : [...careerSkills, resolvedSkill],\n        termSkills: [...termSkills, resolvedSkill]\n    };\n};\n"
export const SHARED_IDS_JS = "const asNonEmptyString = (value, label) => {\n    const normalized = value.trim();\n    if (!normalized) {\n        throw new Error(`${label} cannot be empty`);\n    }\n    return normalized;\n};\nexport const asUserId = (value) => asNonEmptyString(value, 'User id');\nexport const asGameId = (value) => asNonEmptyString(value, 'Game id');\nexport const asCharacterId = (value) => asNonEmptyString(value, 'Character id');\nexport const asBoardId = (value) => asNonEmptyString(value, 'Board id');\nexport const asPieceId = (value) => asNonEmptyString(value, 'Piece id');\nexport const asEventId = (value) => asNonEmptyString(value, 'Event id');\n"
export const SHARED_RESULT_JS = "export const ok = (value) => ({\n    ok: true,\n    value\n});\nexport const err = (error) => ({\n    ok: false,\n    error\n});\n"
export const SHARED_UTIL_JS = "export const clamp = (value, min, max) => Math.max(min, Math.min(max, value));\nexport const isObject = (value) => typeof value === 'object' && value !== null && !Array.isArray(value);\nexport const isString = (value) => typeof value === 'string';\nexport const randomChoice = (items, rng) => {\n    if (items.length === 0) {\n        throw new Error('Cannot choose from an empty array');\n    }\n    return items[Math.floor(rng() * items.length)];\n};\nexport const sumBy = (items, project) => items.reduce((sum, item) => sum + project(item), 0);\nexport const minBy = (items, project) => items.reduce((best, item) => best === undefined || project(item) < project(best) ? item : best, undefined);\nexport const maxBy = (items, project) => items.reduce((best, item) => best === undefined || project(item) > project(best) ? item : best, undefined);\nexport const indexBy = (items, project) => Object.fromEntries(items.map((item) => [project(item), item]));\nexport const groupBy = (items, project) => items.reduce((groups, item) => {\n    const key = project(item);\n    groups[key] = groups[key] ?? [];\n    groups[key].push(item);\n    return groups;\n}, {});\nexport const compact = (items) => items.filter((item) => item != null);\nexport const filterMap = (items, project) => items.reduce((acc, item) => {\n    const result = project(item);\n    if (result != null)\n        acc.push(result);\n    return acc;\n}, []);\nexport const uniqueBy = (items, project) => {\n    const seen = new Set();\n    return items.filter((item) => {\n        const key = project(item);\n        if (seen.has(key))\n            return false;\n        seen.add(key);\n        return true;\n    });\n};\nexport const mapValues = (values, project) => Object.fromEntries(Object.entries(values).map(([key, value]) => [key, project(value, key)]));\nexport const partition = (items, predicate) => items.reduce(([matches, rest], item) => {\n    const target = predicate(item) ? matches : rest;\n    target.push(item);\n    return [matches, rest];\n}, [[], []]);\n"
export const CLIENT_MANIFEST = "{\n  \"name\": \"Cepheus Online\",\n  \"short_name\": \"Cepheus\",\n  \"description\": \"A lightweight sci-fi tabletop for Cepheus Engine games.\",\n  \"id\": \"/\",\n  \"start_url\": \"/\",\n  \"scope\": \"/\",\n  \"display\": \"standalone\",\n  \"display_override\": [\"window-controls-overlay\", \"standalone\", \"browser\"],\n  \"orientation\": \"any\",\n  \"background_color\": \"#020504\",\n  \"theme_color\": \"#020504\",\n  \"icons\": [\n    {\n      \"src\": \"/icon.svg\",\n      \"sizes\": \"any\",\n      \"type\": \"image/svg+xml\",\n      \"purpose\": \"any\"\n    },\n    {\n      \"src\": \"/icon-maskable.svg\",\n      \"sizes\": \"any\",\n      \"type\": \"image/svg+xml\",\n      \"purpose\": \"maskable\"\n    }\n  ],\n  \"categories\": [\"games\", \"entertainment\"],\n  \"launch_handler\": {\n    \"client_mode\": \"navigate-existing\"\n  },\n  \"shortcuts\": [\n    {\n      \"name\": \"Open demo room\",\n      \"short_name\": \"Demo\",\n      \"description\": \"Open the local demo tabletop room.\",\n      \"url\": \"/?game=demo-room\",\n      \"icons\": [\n        {\n          \"src\": \"/icon.svg\",\n          \"sizes\": \"any\",\n          \"type\": \"image/svg+xml\",\n          \"purpose\": \"any\"\n        },\n        {\n          \"src\": \"/icon-maskable.svg\",\n          \"sizes\": \"any\",\n          \"type\": \"image/svg+xml\",\n          \"purpose\": \"maskable\"\n        }\n      ]\n    }\n  ]\n}\n"
